import type { Drill } from "./types";

// Consultant / early drills, keyed by module slug — 25 per module.
// Pitched at a consulting analyst or associate: workstream updates to the
// engagement manager, slide headlines, client data requests, interview
// synthesis, and flagging analysis risks. Merged into course.ts.
export const CONSULTANT_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-con-early-01","level":"early","profession":"consultant","title":"The workstream update that narrates","scenario":"Your engagement manager pings you at 5pm for a status on the pricing workstream. The real news: the analysis is done and supports the hypothesis. Your draft walks through every data pull and pivot table before saying so.","task":"Write a 2-sentence update that leads with the headline finding.","tips":["First sentence: the status and the finding, not the activity.","The EM decides what to tell the partner from your first line.","Data mechanics are support — mention them only if asked."],"focus":["structure","concision"],"placeholder":"Pricing analysis is done and supports the hypothesis —"},
    {"id":"lead-con-early-02","level":"early","profession":"consultant","title":"Blocked on client data","scenario":"You can't finish the cost benchmarking because the client's finance team hasn't sent the plant-level data, and only your EM can escalate. You start drafting a long Slack message about everything you tried first.","task":"Write a Slack message to your EM that puts the ask in the first sentence.","tips":["Lead with what you need and who can unblock it.","What you already tried is support — one line, after the ask.","Say what slips if it isn't resolved by when."],"focus":["clarity","impact"],"placeholder":"I need you to escalate the plant-level cost data —"},
    {"id":"lead-con-early-03","level":"early","profession":"consultant","title":"The good news buried in process","scenario":"Your EM asked for an update on the market sizing. The real news: it's finished a day early and the number is defensible. Your draft opens with how tricky the segment definitions were.","task":"Write a 2-3 sentence email that leads with the result.","tips":["Put 'done, a day early' in sentence one.","Don't make the EM read to the end for the punchline.","The methodology story is optional detail below."],"focus":["structure","concision"]},
    {"id":"lead-con-early-04","level":"early","profession":"consultant","title":"The slide title that says nothing","scenario":"Your page is titled 'Customer survey results.' The chart actually shows that two-thirds of churned customers left over service issues, not price. The title carries none of that.","task":"Rewrite the slide headline so it states the takeaway, not the topic.","tips":["A headline is a full sentence with a verdict.","If someone reads only titles, they should still get the story.","Keep it under about 12 words."],"focus":["clarity","impact"],"placeholder":"Service failures, not price, drive two-thirds of churn"},
    {"id":"lead-con-early-05","level":"early","profession":"consultant","title":"The question buried in setup","scenario":"You want to ask the senior associate whether to size the market top-down or bottom-up. You've drafted three paragraphs about the data sources before the actual question appears.","task":"Rewrite the message so the question comes first.","tips":["Ask the question in sentence one.","Give just enough context for them to answer — no more.","A crisp question gets answered between meetings; an essay waits until tomorrow."],"focus":["concision","clarity"],"placeholder":"Quick question: top-down or bottom-up for the sizing?"},
    {"id":"lead-con-early-06","level":"early","profession":"consultant","title":"The data-request nudge","scenario":"You sent the client's ops analyst a data request three days ago and heard nothing. The deck freezes Thursday. Your follow-up draft opens with apologies and 'just checking in when you get a chance.'","task":"Write a follow-up that leads with the specific ask and the deadline.","tips":["Name exactly what you need and by when.","Cut the apologetic warm-up — it buries the deadline.","Offer one easy way to make it smaller if the full pull is hard."],"focus":["clarity","impact"]},
    {"id":"lead-con-early-07","level":"early","profession":"consultant","title":"The date they actually asked for","scenario":"Your EM asks when the competitor scan will be ready. You know the answer is Wednesday, but you start explaining the two competitors with paywalled financials.","task":"Write a reply that gives the date first, then the one caveat.","tips":["Lead with the date — that is the question asked.","One caveat, one sentence, after the headline.","Don't make the EM dig for the answer."],"focus":["precision","structure"],"placeholder":"Wednesday, with one gap —"},
    {"id":"lead-con-early-08","level":"early","profession":"consultant","title":"The model error that matters","scenario":"You found an error in the shared Excel model: a hardcoded cell is overstating the savings estimate by roughly 20%. That number is already on a page the partner reviewed. Your draft explains how you found it before saying what it means.","task":"Write a message that leads with the impact, then the fix.","tips":["First sentence: what's wrong and how big.","Note which pages or numbers it touches.","How you found it is detail — put it last or skip it."],"focus":["impact","clarity"],"placeholder":"The savings estimate is overstated ~20% — a hardcoded cell in the model."},
    {"id":"lead-con-early-09","level":"early","profession":"consultant","title":"The Friday check-in that meanders","scenario":"At the Friday team check-in you have 60 seconds. This week you finished the interview synthesis and closed two data gaps, but your notes start with a recap of every meeting you attended.","task":"Write the 1-2 sentence opening of your check-in that leads with what you delivered.","tips":["Lead with outcomes, not calendar activity.","One crisp summary sentence, then anything the team must know.","If nothing is blocked, say so in three words."],"focus":["concision","structure"],"placeholder":"Interview synthesis is done and both data gaps are closed —"},
    {"id":"lead-con-early-10","level":"early","profession":"consultant","title":"The slip you don't want to say","scenario":"The interview synthesis you promised for Tuesday won't be ready until Thursday — two experts rescheduled. You're nervous, so your draft to the EM opens with the scheduling saga before admitting the new date.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["Lead with the new date — that's what the EM plans around.","Reasons come after, in one sentence.","Say what you'll do to protect the Friday deck."],"focus":["clarity","impact"],"placeholder":"The interview synthesis will land Thursday, not Tuesday."},
    {"id":"lead-con-early-11","level":"early","profession":"consultant","title":"The recommendation hiding in pros and cons","scenario":"The senior associate asked which survey vendor to use. You compared three and have a clear pick, but your reply walks through every vendor's pros and cons before recommending one.","task":"Rewrite so your recommendation comes first, with the top two reasons after.","tips":["State your pick in sentence one.","Two reasons beat six — pick the ones that decide it.","The full comparison can live in an attachment."],"focus":["structure","clarity"],"placeholder":"Go with Vendor B —"},
    {"id":"lead-con-early-12","level":"early","profession":"consultant","title":"The interview readout opener","scenario":"You're giving the team a 5-minute readout on eight customer interviews. Your draft opens with who you talked to and how you scheduled them, before any of what they said.","task":"Write the first two sentences of the readout, leading with the strongest takeaway.","tips":["Open with the finding, not the fieldwork.","Who you interviewed is one clause, not one minute.","Let the team hear the point before the process."],"focus":["structure","impact"]},
    {"id":"lead-con-early-13","level":"early","profession":"consultant","title":"The QA favor","scenario":"You need a fellow analyst to check your numbers on five pages before they go to the partner at 4pm. Your draft explains the whole history of the pages before getting to the ask.","task":"Write a Slack message that leads with the specific request and the deadline.","tips":["Lead with the ask: five pages, numbers check, by 3:30.","Context is one sentence, after.","Make it easy to say yes or counter with a time."],"focus":["clarity","concision"],"placeholder":"Could you check the numbers on 5 pages before 3:30?"},
    {"id":"lead-con-early-14","level":"early","profession":"consultant","title":"The roll-off handoff","scenario":"You're rolling off the engagement Friday and handing your workstream to another analyst. There's one live risk — the client's data refresh lands Monday and the model must be rerun. Your handoff note starts with a calm tour of everything that's fine.","task":"Write a handoff note that leads with the one thing they must not miss.","tips":["First line: the live risk and the action it needs.","Everything stable can come after, grouped briefly.","If they read one line, it should be the Monday rerun."],"focus":["precision","structure"],"placeholder":"One thing you must do: rerun the model when the client refresh lands Monday."},
    {"id":"lead-con-early-15","level":"early","profession":"consultant","title":"The soft-pedaled disagreement","scenario":"In the team problem-solving session doc, the senior associate proposed cutting the customer interviews to save time. You think that guts the evidence base. Your draft comment spends four sentences agreeing before hinting at the concern.","task":"Write a comment that states your concern first, then the reasoning.","tips":["Lead with the concern, plainly and respectfully.","Then the reasoning and an alternative.","Cushioning that buries the point isn't politeness — it's noise."],"focus":["clarity","impact"]},
    {"id":"lead-con-early-16","level":"early","profession":"consultant","title":"The survey dump","scenario":"The survey results came back and the headline is clear: willingness to pay is 15% below the client's current price point. Your message to the team pastes four charts before saying what they mean.","task":"Write a message that leads with the conclusion, then points to the evidence.","tips":["First sentence: the takeaway in plain words.","Charts are evidence — reference them after.","Tell the team what it means for the storyline."],"focus":["clarity","structure"],"placeholder":"Willingness to pay comes in 15% below current price —"},
    {"id":"lead-con-early-17","level":"early","profession":"consultant","title":"The keep-going-or-stop check","scenario":"You're halfway through cleaning a messy client dataset and it's taking far longer than planned. You want the EM's call: keep cleaning for full coverage, or run with the 70% that's clean. Your draft describes the data problems in detail before asking.","task":"Write a message that puts the decision you need first.","tips":["Lead with the decision: full clean (2 more days) or run with 70% now.","Give the tradeoff in one sentence each.","Bound the choice — don't hand over an open problem."],"focus":["clarity","concision"],"placeholder":"Need your call: keep cleaning (2 more days) or run the analysis on the 70% that's clean?"},
    {"id":"lead-con-early-18","level":"early","profession":"consultant","title":"The one-line client ask","scenario":"You're emailing your client counterpart in operations for the shift schedules from three plants. Your draft opens with two paragraphs about the project's goals before naming what you need.","task":"Write an email where the first sentence states exactly what you need and by when.","tips":["Lead with the ask: which files, which plants, what date.","One line of why is plenty — they know the project.","End with the easiest way to send it."],"focus":["clarity","precision"],"placeholder":"Could you send the shift schedules for the three pilot plants by Wednesday?"},
    {"id":"lead-con-early-19","level":"early","profession":"consultant","title":"The yes hiding in paragraphs","scenario":"Your EM asks one question in Slack: can we cut the regional deep-dive page without breaking the story? You know it can go, but your reply drafts three paragraphs of context before saying yes.","task":"Write a reply that answers first, then adds the one caveat.","tips":["Answer in the first word or two.","Caveats follow the answer, briefly.","Don't make the EM re-read to find your verdict."],"focus":["concision","clarity"],"placeholder":"Yes — it can go. One caveat:"},
    {"id":"lead-con-early-20","level":"early","profession":"consultant","title":"The estimate that tripled","scenario":"The benchmarking task the team scoped as one day is clearly three: the client's categories don't match the benchmark database. You need to flag it now, but your draft eases in with how unusual the client's chart of accounts is.","task":"Write a heads-up to your EM that leads with the revised estimate.","tips":["Lead with the new number: three days, not one.","Why it grew is one sentence of support.","Offer an option: partial mapping by tomorrow, full by Thursday."],"focus":["precision","impact"],"placeholder":"Heads-up: the benchmarking is a 3-day task, not 1."},
    {"id":"lead-con-early-21","level":"early","profession":"consultant","title":"The team retro point","scenario":"In the end-of-phase team retro you want to raise that slide requests without a sketch or headline cost the team rework this phase. Your draft starts with a long story about one specific page before naming the pattern.","task":"Write a retro comment that names the pattern first, then the example.","tips":["State the pattern up front: unsketched requests caused rework.","Use the specific page as evidence, in one sentence.","End with the change you're proposing."],"focus":["structure","clarity"]},
    {"id":"lead-con-early-22","level":"early","profession":"consultant","title":"The overwritten master deck","scenario":"You accidentally saved over the master version of the client deck with an older copy. You've restored last night's version, but two hours of the senior associate's edits are gone. Your instinct is to explain the file-naming mixup before saying what happened.","task":"Write a message that leads with the current status and what was lost.","tips":["First line: what happened and where things stand now.","Name exactly what's lost so people can act.","The how is one sentence, and so is the fix to prevent it."],"focus":["clarity","impact"],"placeholder":"I overwrote the master deck — restored to last night, but your edits from this morning are gone."},
    {"id":"lead-con-early-23","level":"early","profession":"consultant","title":"The vague coffee-chat request","scenario":"You want 15 minutes with your EM to talk about what you should be developing this engagement. Your draft dances around it: 'if you ever have a sec, would love to pick your brain about some things.'","task":"Write a request that states the purpose and the time you need up front.","tips":["Lead with what the conversation is for and how long.","Vague asks get deprioritized; specific ones get calendared.","Suggest two concrete times."],"focus":["clarity","precision"],"placeholder":"Could I grab 15 minutes this week to talk about my development goals for this study?"},
    {"id":"lead-con-early-24","level":"early","profession":"consultant","title":"The two-chart decision","scenario":"You've built two versions of the key exhibit — a waterfall and a stacked bar — and need the senior associate's pick by tomorrow morning so production can finish. Your draft explains the design tradeoffs for a paragraph before presenting the choice.","task":"Write a message that leads with the decision and deadline, then the two options in one line each.","tips":["Open with the decision needed and by when.","Then Option A vs Option B, one line each.","State your own lean — don't just hand over a menu."],"focus":["structure","clarity"],"placeholder":"Need your pick by 9am: waterfall or stacked bar for the savings exhibit."},
    {"id":"lead-con-early-25","level":"early","profession":"consultant","title":"The thank-you that hides the favor","scenario":"The senior associate stayed late yesterday to help you fix the model. Now you need one more thing — a 10-minute read of your interview guide before tomorrow's calls. Your draft is all gratitude with the ask buried in the last line.","task":"Write a message that makes the new ask clear early while still being gracious.","tips":["Pair the thanks and the ask in the first two lines.","Don't make them read past the gratitude to find the favor.","Name the time cost: 10 minutes, before 9am."],"focus":["clarity","audience"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-con-early-01","level":"early","profession":"consultant","title":"The update your EM can use","scenario":"Your EM asks how the churn analysis is going. You want to reply: \"I've deduplicated the customer file, rebuilt the cohort logic, and I'm re-cutting the tenure bands.\" The EM needs to know one thing: will there be a finding to show the partner Thursday?","task":"Rewrite your update in 2-3 sentences around what the EM actually needs.","tips":["Lead with whether Thursday holds and what the emerging finding is.","Translate the data work into progress the EM can report upward.","Mention mechanics only if they change the date."],"focus":["audience","clarity"],"placeholder":"On track for Thursday, and the early cut shows…"},
    {"id":"audience-con-early-02","level":"early","profession":"consultant","title":"Explaining the analysis to the client analyst","scenario":"Your client counterpart — an operations analyst — asks what you're doing with the data she sent. Your honest answer is full of consulting shorthand: cohort analysis, MECE segmentation, hypothesis tree. She just wants to know what her data will be used to show.","task":"Write a 2-3 sentence explanation in her language, not yours.","tips":["Drop the framework names; describe what the output will show.","Connect it to something she cares about — her plants, her metrics.","Say when she'll see the result."],"focus":["audience","clarity"]},
    {"id":"audience-con-early-03","level":"early","profession":"consultant","title":"The production handoff","scenario":"You're sending five pages to the graphics team overnight. Your instinct is to write \"clean these up.\" The production designer needs to know what each page must communicate, what can move, and what must not change.","task":"Write a 3-4 sentence handoff note framed around what the designer needs to protect and improve.","tips":["Lead with the one thing each page must still say when they're done.","Flag what's locked (numbers, footnotes) vs. flexible (layout).","Give the deadline and where to put questions."],"focus":["audience","structure"]},
    {"id":"audience-con-early-04","level":"early","profession":"consultant","title":"The question pitched at partner altitude","scenario":"You have 30 seconds with the partner after the team call and want guidance on your workstream. Your drafted question is about which Excel lookup approach to use — an EM question, not a partner question.","task":"Write the one question you'd actually ask the partner, calibrated to what only they can answer.","tips":["Partners answer direction and client questions, not tooling questions.","Ask about the 'so what', the client's reaction, or where the bar is.","One question, one sentence."],"focus":["audience","precision"],"placeholder":"When you show this to the CFO, what will she push on hardest?"},
    {"id":"audience-con-early-05","level":"early","profession":"consultant","title":"The IT data request","scenario":"You need transaction-level sales data from the client's IT team. Your draft asks for \"the raw revenue cube with SKU-level granularity, ideally denormalized.\" The IT contact works in their ERP's terms, not yours, and has never seen your project.","task":"Rewrite the request in 2-3 sentences using terms the IT contact can act on.","tips":["Name the system, the tables or reports, the fields, and the date range.","Say the format that works (extract, export, report) — not your ideal shape.","One line on why, so they can prioritize it."],"focus":["audience","precision"]},
    {"id":"audience-con-early-06","level":"early","profession":"consultant","title":"The shorthand that excludes the new joiner","scenario":"A new analyst joined the team this morning. You're writing her a note about a task, and you almost reference \"the Friday deck,\" \"workstream 2,\" and \"the Marseille issue\" — shorthand she can't decode yet.","task":"Rewrite the note (3-4 sentences) so it assumes no project history.","tips":["Spell out the shorthand the first time you use it.","Give the one line of context that makes the task make sense.","Point her to where the referenced files live."],"focus":["audience","clarity"]},
    {"id":"audience-con-early-07","level":"early","profession":"consultant","title":"The expert prep email","scenario":"Tomorrow you interview a former plant director through an expert network. Your draft email lists your fifteen internal research questions verbatim. He needs to know the topic, the time, and roughly what to think about — not your question tree.","task":"Write a 3-4 sentence prep note pitched at what the expert needs.","tips":["Name the topic areas in his terms, not your hypothesis labels.","Keep it to 3 bullets max — he prepares in five minutes.","Confirm logistics: time, length, who's calling whom."],"focus":["audience","concision"]},
    {"id":"audience-con-early-08","level":"early","profession":"consultant","title":"Two audiences, one delay","scenario":"The survey field date slipped three days. You have to tell your EM and your client counterpart. The EM cares about the deck timeline; the client contact cares about whether her stakeholders were over-promised. One message won't fit both.","task":"Write the 2-sentence version for ONE of them — and pick which one first.","tips":["Choose the primary audience and write only for them.","Lead with the consequence that matters to that reader.","What you'd tell the other reader is a different message."],"focus":["audience","impact"]},
    {"id":"audience-con-early-09","level":"early","profession":"consultant","title":"The finding for the plant manager","scenario":"Your analysis shows the client's Tuesday shift changeovers lose 40 minutes to a scheduling gap. You're presenting it to the plant manager who runs those shifts. Your draft opens with your data methodology and sample period.","task":"Write a 2-3 sentence version that starts from what the plant manager sees on the floor.","tips":["Open with the operational reality he'd recognize, then the number.","Methodology goes at the end or in his follow-up questions.","Frame it as something fixable, not an accusation."],"focus":["audience","impact"],"placeholder":"You've probably felt Tuesday changeovers running long — the data shows…"},
    {"id":"audience-con-early-10","level":"early","profession":"consultant","title":"The finance team's language","scenario":"You need the client's FP&A team to validate your cost allocations. Your draft describes your \"bottom-up build with activity-based splits.\" They think in cost centers, GL accounts, and budget lines.","task":"Write a 2-3 sentence request in their vocabulary.","tips":["Ask them to check the mapping from their cost centers to your categories.","Attach the thing to react to — never ask them to imagine it.","Give a bounded effort estimate: 20 minutes, five lines."],"focus":["audience","precision"]},
    {"id":"audience-con-early-11","level":"early","profession":"consultant","title":"Altitude for the steering committee page","scenario":"You drafted a page for the steering committee pre-read with 14 rows of workstream detail. Steerco members skim; they need status, decisions required, and risks — in ten seconds.","task":"Write the three lines that should replace the 14 rows.","tips":["Steerco altitude: on track or not, what decision is needed, what's at risk.","Detail lives in the appendix for whoever wants it.","If no decision is needed, say that in line one."],"focus":["audience","concision"],"placeholder":"All workstreams on track. One decision needed:"},
    {"id":"audience-con-early-12","level":"early","profession":"consultant","title":"The jargon-free framework","scenario":"Your client counterpart asks why you keep reorganizing her category list. The honest answer involves 'MECE' and 'collectively exhaustive.' She'll switch off at the first acronym.","task":"Explain in 2 sentences, in plain words, why the categories need to not overlap and not leave gaps.","tips":["Use a concrete consequence: double-counting, missed spend.","No framework names — describe the property, not the label.","Anchor it in her data, not consulting theory."],"focus":["audience","clarity"]},
    {"id":"audience-con-early-13","level":"early","profession":"consultant","title":"The interview request to a busy operator","scenario":"You need 45 minutes with the client's warehouse supervisor, who is skeptical of consultants and busy with peak season. Your draft leads with the project's strategic objectives.","task":"Write a 3-sentence interview request built around his time and his stake.","tips":["Lead with the respect for his time: 45 minutes, his choice of slot.","Say what's in it for his operation, concretely.","Make clear you want his experience, not to audit him."],"focus":["audience","impact"]},
    {"id":"audience-con-early-14","level":"early","profession":"consultant","title":"Explaining the sample limitation","scenario":"Your survey covered 200 customers, skewed toward the largest accounts. The client's marketing lead — not a data person — needs to understand what the results can and can't tell her before she quotes them internally.","task":"Write 2-3 sentences she can safely repeat, in plain terms.","tips":["Say who the results speak for and who they don't.","Give her the safe sentence to quote verbatim.","No statistics vocabulary — 'mostly large accounts' beats 'skewed sample'."],"focus":["audience","precision"],"placeholder":"These results reflect our larger accounts —"},
    {"id":"audience-con-early-15","level":"early","profession":"consultant","title":"The staffing heads-up the EM can act on","scenario":"You've been double-booked: the other engagement you support wants you Thursday, the same day as this team's client working session. Your draft to the EM narrates the whole staffing history. The EM needs the conflict, the date, and the options.","task":"Write a 3-sentence note giving the EM exactly what they need to resolve it.","tips":["Lead with the conflict and the date.","Give two resolution options with your recommendation.","The staffing backstory is not the EM's problem — cut it."],"focus":["audience","structure"]},
    {"id":"audience-con-early-16","level":"early","profession":"consultant","title":"The pre-read vs. the appendix","scenario":"You've been asked to turn your 20-page analysis into a pre-read for the client working session. Your instinct is to compress all 20 pages. The attendees need only what they must digest before the room: the finding, the choice to be made, and the numbers behind it.","task":"Write the 3-4 sentence cover note that tells attendees what to read and why.","tips":["Tell them the one decision the session will make.","Point to the 3 pages that matter; the rest is reference.","Reading time honesty: 'ten minutes' builds trust."],"focus":["audience","structure"]},
    {"id":"audience-con-early-17","level":"early","profession":"consultant","title":"The NDA question for legal","scenario":"You want to reuse an industry benchmark from a previous client study, and you need the firm's risk team to confirm it's allowed. Your draft is a project narrative. They need the source, the intended use, and the confidentiality terms.","task":"Write a 3-sentence request giving legal exactly the facts they decide on.","tips":["Name the artifact, its origin, and where it would appear.","Ask the specific question: can we use it, and with what attribution?","Give your deadline and what happens if the answer is no."],"focus":["audience","precision"]},
    {"id":"audience-con-early-18","level":"early","profession":"consultant","title":"Model assumptions for the client's finance team","scenario":"The client's finance director will review your savings model tomorrow. Your assumptions page lists 22 items in consulting shorthand. She will look for the five assumptions that drive the number and challenge those.","task":"Write the 3 lines you'd put at the top of the assumptions page for her.","tips":["Surface the assumptions that move the answer most.","State each in her terms: rates, headcounts, ramp timelines.","Invite the challenge: mark which ones you're least sure of."],"focus":["audience","precision"],"placeholder":"Three assumptions drive 80% of the savings number:"},
    {"id":"audience-con-early-19","level":"early","profession":"consultant","title":"The onboarding note for your successor","scenario":"A new analyst takes over your workstream Monday. You're drafting the handover and keep writing for someone who already knows the project — referencing decisions by date and people by first name.","task":"Write the opening 3-4 sentences of a handover pitched at someone with zero context.","tips":["Start with what the workstream answers and for whom.","Introduce people with role, not just name.","Link every referenced file — 'the model' means nothing yet."],"focus":["audience","structure"]},
    {"id":"audience-con-early-20","level":"early","profession":"consultant","title":"What did the survey say?","scenario":"Your client counterpart catches you in the hallway: \"So what did the survey say?\" You have 30 seconds and she cares about one thing — whether her team's pricing proposal survives.","task":"Give a 2-sentence spoken answer built around her stake.","tips":["Answer her real question first: what it means for the pricing proposal.","One supporting number, not five.","Offer the full readout as the follow-up, not the answer."],"focus":["audience","concision"],"placeholder":"Short version: the pricing proposal holds, with one adjustment —"},
    {"id":"audience-con-early-21","level":"early","profession":"consultant","title":"The recruiter-style intro, fixed","scenario":"You're introducing yourself at the client kickoff. Your draft recites your firm tenure and prior industries. The client team wants to know one thing: what you'll be doing with them and what you'll need from them.","task":"Write a 2-3 sentence self-intro built for what the client team needs to know.","tips":["Lead with your role on this project, not your CV.","Name what you'll be asking them for in the coming weeks.","Keep credentials to a clause, if at all."],"focus":["audience","concision"]},
    {"id":"audience-con-early-22","level":"early","profession":"consultant","title":"Translating the expert's jargon","scenario":"Your expert interview yielded a great quote: \"Their OEE is stuck because they never rebalanced takt after the line extension.\" It's going in the readout, but the client's commercial team won't parse a word of it.","task":"Rewrite the insight in 1-2 sentences a commercial audience understands.","tips":["Replace each technical term with its consequence.","Keep the expert's authority — 'a former plant director told us'.","Test: would a salesperson repeat it correctly?"],"focus":["audience","clarity"]},
    {"id":"audience-con-early-23","level":"early","profession":"consultant","title":"Scheduling through the chief of staff","scenario":"You need 45 minutes with the client's COO for an interview, and the route is her chief of staff. Your draft explains your entire interview guide. The chief of staff needs the purpose, the time, the window, and why it's worth the COO's calendar.","task":"Write a 3-sentence scheduling request pitched at the gatekeeper.","tips":["Lead with what the meeting is and how long.","One sentence on why it needs the COO specifically.","Offer flexibility: windows, video, or a shortened version."],"focus":["audience","concision"]},
    {"id":"audience-con-early-24","level":"early","profession":"consultant","title":"The same finding, up and down","scenario":"Your finding: consolidating two distribution centers saves $3M but adds a day to delivery times in the northeast. You're writing one version for the partner. The partner cares about the client conversation it triggers, not the logistics detail.","task":"Write the 2-sentence partner version.","tips":["Lead with the tension the client must decide on: savings vs. service.","Size both sides in one line each.","Flag what the client sponsor will likely say."],"focus":["audience","impact"],"placeholder":"This sets up a real tradeoff for the client: $3M in savings against…"},
    {"id":"audience-con-early-25","level":"early","profession":"consultant","title":"The working-level ally","scenario":"The client analyst who pulls your data has started sending things late and terse. You suspect she feels like a free data service. Your next request is a chance to reset the relationship.","task":"Write a 3-4 sentence request that treats her as a collaborator, not a vendor.","tips":["Show her what her last extract made possible — close the loop.","Ask her view, not just her files: she knows the data's quirks.","Keep the ask specific and bounded so it's easy to fit in."],"focus":["audience","impact"]}
  ],
  "structure-that-carries": [
    {"id":"structure-con-early-01","level":"early","profession":"consultant","title":"The workstream update with one governing idea","scenario":"Your weekly workstream email to the EM lists nine things you did, in the order you did them. There's a story in there — the analysis is done, one risk remains — but it's scattered across the nine bullets.","task":"Restructure the update under one governing sentence with at most three supporting points.","tips":["Open with the single message the EM should take away.","Group the nine items into three buckets, not a flat list.","Each bucket earns its place by supporting the top line."],"focus":["structure","clarity"],"placeholder":"The pricing workstream is on track for Thursday, with one open risk:"},
    {"id":"structure-con-early-02","level":"early","profession":"consultant","title":"SCQA for the finding memo","scenario":"You're writing a short memo on why the client's northeast region underperforms. You have the answer but no on-ramp — the reader lands in the middle of your analysis with no idea why it matters.","task":"Write the opening of the memo using Situation, Complication, Question, Answer — one sentence each.","tips":["Situation: the stable fact everyone agrees on.","Complication: what changed or broke that raises the stakes.","Question then Answer: the one question, then your finding."],"focus":["structure","clarity"]},
    {"id":"structure-con-early-03","level":"early","profession":"consultant","title":"PREP for the stand-up answer","scenario":"At the team stand-up, the EM asks whether the cost model is trustworthy. You tend to ramble through caveats. You want a spoken answer with a spine.","task":"Answer aloud in the PREP shape: Point, Reason, Example, Point — four sentences.","tips":["Point: your verdict on the model in one sentence.","Reason then Example: why, then one concrete instance.","Return to the Point so it lands."],"focus":["structure","concision"],"placeholder":"The model is trustworthy for the top three cost lines. The reason is…"},
    {"id":"structure-con-early-04","level":"early","profession":"consultant","title":"The messy risk list, grouped","scenario":"You've jotted eleven project risks in the order they occurred to you: data gaps, a skeptical stakeholder, a tight timeline, an untested assumption, and so on. Presented flat, the EM can't see the shape.","task":"Group the eleven into three or four labeled categories with a one-line header each.","tips":["Find the natural buckets: data, stakeholders, timeline, method.","Name each bucket so the label carries meaning.","Order buckets by which threatens the deck most."],"focus":["structure","clarity"]},
    {"id":"structure-con-early-05","level":"early","profession":"consultant","title":"The horizontal storyline","scenario":"Your five-page section reads as five unrelated exhibits. Read as titles-only, they don't tell a story — they're just topics: 'market size,' 'competitors,' 'margins,' 'customers,' 'risks.'","task":"Rewrite the five page headlines so, read in sequence, they make one argument.","tips":["Each headline is a sentence, and together they form a logic chain.","The titles alone should argue the recommendation.","Cut or merge any page whose headline doesn't advance the line."],"focus":["structure","impact"]},
    {"id":"structure-con-early-06","level":"early","profession":"consultant","title":"The pyramid for the recommendation","scenario":"You're recommending the client exit a product line. You have a dozen reasons of varying weight. Dumped as a list, the recommendation looks equally supported by trivia and by the decisive facts.","task":"Structure the argument as one recommendation supported by exactly three pillars.","tips":["Force it to three pillars — the discipline reveals what matters.","Each pillar should be a distinct kind of reason, not a variation.","Trivia becomes sub-support under a pillar, or gets cut."],"focus":["structure","clarity"],"placeholder":"Exit the product line. Three reasons make the case:"},
    {"id":"structure-con-early-07","level":"early","profession":"consultant","title":"The interview synthesis with a spine","scenario":"You interviewed ten customers and your notes are ten separate summaries. The team readout needs themes, not a person-by-person tour that makes everyone lose the thread by the fourth interviewee.","task":"Reorganize the synthesis around three themes, each drawing on multiple interviews.","tips":["Lead with the theme, then cite who said it.","Three themes carry more than ten profiles.","Note where interviews disagree — that's a finding, not noise."],"focus":["structure","precision"]},
    {"id":"structure-con-early-08","level":"early","profession":"consultant","title":"The email that needs headers","scenario":"You're sending the EM a long email covering status, two decisions needed, and a risk. It's one unbroken block; the two decisions could easily get missed in the wall of text.","task":"Restructure the email with signposted sections so the decisions can't be missed.","tips":["Use a header line per section: Status, Decisions needed, Risk.","Put the decisions where the eye lands, not buried mid-paragraph.","Number the decisions so replies can reference them."],"focus":["structure","clarity"]},
    {"id":"structure-con-early-09","level":"early","profession":"consultant","title":"The exhibit that needs an action title","scenario":"Your chart shows procurement spend split across 40 suppliers, with the top 5 holding 60%. The current title is 'Supplier spend distribution.' The exhibit has a point but the structure doesn't surface it.","task":"Give the exhibit an action title and one supporting call-out that structures how to read it.","tips":["Title states the takeaway; call-out points to where it's visible.","Guide the eye: what to look at first, then second.","The reader should get it without you narrating."],"focus":["structure","impact"],"placeholder":"Five suppliers control 60% of spend — a consolidation opportunity"},
    {"id":"structure-con-early-10","level":"early","profession":"consultant","title":"The verbal walk-through order","scenario":"You have to walk the team through your analysis live. You know every detail but no path — you keep jumping between the data, the method, and the finding, and people get lost.","task":"Write the 4-step order you'll speak in, one line per step.","tips":["Decide the sequence before you open your mouth.","Finding first, then the two pieces of evidence, then the caveat.","Announce the structure so listeners can follow: 'three things.'"],"focus":["structure","clarity"]},
    {"id":"structure-con-early-11","level":"early","profession":"consultant","title":"Parallel structure in the bullets","scenario":"Your slide has five bullets: one starts with a verb, one is a noun phrase, one is a full sentence, one is a fragment. They cover good content but read as a jumble because nothing is parallel.","task":"Rewrite the five bullets in parallel grammatical form.","tips":["Pick one form — all verb-first, or all noun phrases.","Parallel form signals the items are the same kind of thing.","Trim each to roughly the same length."],"focus":["structure","concision"]},
    {"id":"structure-con-early-12","level":"early","profession":"consultant","title":"The data request, sequenced","scenario":"You need six datasets from the client, but some depend on others and some are urgent. Your draft lists them in a random order, so the client can't tell what to send first.","task":"Restructure the request into a sequenced, prioritized list with a one-line reason each.","tips":["Order by what you need first and what unblocks the most.","Group by owner if different teams hold different sets.","Mark the two that are on the critical path."],"focus":["structure","precision"]},
    {"id":"structure-con-early-13","level":"early","profession":"consultant","title":"SCQA to open the client working session","scenario":"You're drafting the opening two minutes of a client working session on distribution. If you start in the detail, the room won't know why they're there. You need a frame that lands everyone on the same question.","task":"Write the opening using Situation-Complication-Question, ending on the question the session will answer.","tips":["Situation: what the client already knows and accepts.","Complication: the new pressure that makes today necessary.","Question: the single decision this session exists to make."],"focus":["structure","audience"],"placeholder":"Today the network runs on five DCs. Volume has grown 30% since that design —"},
    {"id":"structure-con-early-14","level":"early","profession":"consultant","title":"The 'so what' ladder","scenario":"Your page has three facts stacked: the client's inventory turns are 4x, the industry median is 7x, and holding costs are 12% of revenue. Each is true but the structure stops at facts and never climbs to the implication.","task":"Restructure the three facts into a ladder that ends in a single implication.","tips":["Order facts so each sets up the next.","The top of the ladder is the 'so what', stated plainly.","If the facts don't converge on one point, cut the stray one."],"focus":["structure","impact"]},
    {"id":"structure-con-early-15","level":"early","profession":"consultant","title":"The appendix that ate the story","scenario":"You built 18 pages. Only 6 carry the argument; 12 are backup. Right now they're interleaved, so the reader can't tell the storyline from the support and loses the thread.","task":"Describe the structure: which 6 pages form the spine and how the 12 attach as backup.","tips":["Name the 6-page storyline in one sentence each.","Move backup behind a divider — reachable, not in the way.","The spine should read cleanly if the backup vanished."],"focus":["structure","concision"]},
    {"id":"structure-con-early-16","level":"early","profession":"consultant","title":"The status that mixes altitudes","scenario":"Your update to the EM jumps between 'the deck is on track' and 'cell F42 had a formula error.' High-level status and low-level detail are tangled, so the EM can't skim for what matters.","task":"Restructure so headline status sits on top and detail is clearly subordinate.","tips":["Top line: the status the EM reports upward.","Detail indents under it, for whoever wants to dig.","Don't make the reader sort altitude — do it for them."],"focus":["structure","audience"]},
    {"id":"structure-con-early-17","level":"early","profession":"consultant","title":"The three-part answer to 'what should we do?'","scenario":"The senior associate asks what the client should do about a shrinking segment. Your answer is a stream of considerations. It needs a spine the associate can repeat to the partner.","task":"Structure a spoken answer as: the recommendation, then three moves under it.","tips":["Lead with the one recommendation.","Then three concrete moves, parallel in form.","Keep each move to a phrase — this is a headline, not a plan."],"focus":["structure","clarity"],"placeholder":"Reposition, don't exit. Three moves:"},
    {"id":"structure-con-early-18","level":"early","profession":"consultant","title":"The messy meeting notes","scenario":"Your client meeting notes are a chronological transcript of who said what. The team needs decisions, actions, and open questions — but those are buried across two pages of back-and-forth.","task":"Restructure the notes into three sections: Decisions, Actions (with owners), Open questions.","tips":["Pull every decision into one place — that's what people check.","Actions need an owner and a date, or they're just wishes.","Open questions become next week's agenda."],"focus":["structure","precision"]},
    {"id":"structure-con-early-19","level":"early","profession":"consultant","title":"The hypothesis tree on a page","scenario":"You're explaining to a new analyst how the team's central hypothesis breaks into sub-questions. You keep listing questions flat, so she can't see which nest under which.","task":"Lay out the structure as one hypothesis with two or three sub-branches, each with its test.","tips":["Top: the one hypothesis in a sentence.","Branches: the sub-questions that would prove or break it.","Under each, the analysis that tests it."],"focus":["structure","clarity"]},
    {"id":"structure-con-early-20","level":"early","profession":"consultant","title":"The recommendation slide's three boxes","scenario":"Your recommendation page is a paragraph. The senior associate wants it as a clean structure the partner can absorb in five seconds: the recommendation and its logic.","task":"Restructure the paragraph into a headline plus three labeled boxes.","tips":["Headline carries the recommendation as a full sentence.","Three boxes: why now, what it takes, what it returns.","Each box is a phrase, not a paragraph."],"focus":["structure","impact"]},
    {"id":"structure-con-early-21","level":"early","profession":"consultant","title":"Ordering by importance, not chronology","scenario":"Your update narrates the week Monday-to-Friday. The most important thing happened Wednesday, so it's stranded in the middle. Chronology is fighting importance.","task":"Reorder the update so the most important item leads, regardless of when it happened.","tips":["Importance beats chronology in an update.","Lead with Wednesday's news; the rest is context.","Time-order is for a diary, not a status."],"focus":["structure","impact"]},
    {"id":"structure-con-early-22","level":"early","profession":"consultant","title":"The nested ask","scenario":"You need three things from the EM: a decision, a review, and an intro to a client contact. Your draft mixes them into one paragraph so it's unclear how many asks there even are.","task":"Restructure into a clearly numbered set of three asks, each with what you need and by when.","tips":["Number them so the reply can address each.","Each ask states the action, the owner, the deadline.","Put the blocking one first."],"focus":["structure","clarity"]},
    {"id":"structure-con-early-23","level":"early","profession":"consultant","title":"The 'grouping' that isn't MECE","scenario":"You've split the client's costs into 'labor, overhead, big items, and other.' The buckets overlap ('big items' could be labor) and 'other' is a dumping ground. The structure leaks.","task":"Regroup the costs into non-overlapping, complete categories with clean labels.","tips":["Buckets must not overlap and must cover everything.","Kill the 'other' bucket by finding real homes for its contents.","A leaky structure hides the finding — a clean one reveals it."],"focus":["structure","precision"]},
    {"id":"structure-con-early-24","level":"early","profession":"consultant","title":"The verbal preview","scenario":"You're about to give a three-minute update and the team is only half-listening. Without a preview, they won't know when the important part is coming and will tune the whole thing out.","task":"Write the one-sentence preview that tells the team the shape of what's coming.","tips":["Announce the number: 'three things, then one ask.'","A preview earns attention for the parts that matter.","Then deliver in exactly the order you promised."],"focus":["structure","audience"],"placeholder":"Three quick things and one decision I need from you —"},
    {"id":"structure-con-early-25","level":"early","profession":"consultant","title":"The findings deck outline","scenario":"You've been asked to draft the skeleton of the phase-end findings deck. You have twenty exhibits and no outline, so you're tempted to just order them by workstream — which buries the argument in org-chart logic.","task":"Write a 5-line outline structured as an argument, naming what each section proves.","tips":["Structure by argument, not by workstream or team.","Each section is a claim the exhibits under it prove.","The outline should read as the executive summary."],"focus":["structure","impact"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-con-early-01","level":"early","profession":"consultant","title":"The hedged status update","scenario":"Your update reads: \"I think the analysis is more or less on track and should probably be ready by Thursday, assuming nothing unexpected comes up.\" The EM can't tell if that's a yes.","task":"Rewrite it in one clean sentence with the hedges cut.","tips":["Cut 'I think', 'more or less', 'should probably'.","If you have a real caveat, name it precisely instead of hedging.","One confident sentence beats three qualified ones."],"focus":["concision","precision"],"placeholder":"The analysis is on track for Thursday."},
    {"id":"concise-con-early-02","level":"early","profession":"consultant","title":"The nominalized finding","scenario":"Your slide note says: \"There is a significant reduction in the utilization of the northeast facilities due to a decline in demand.\" Buried nouns make it heavy and slow.","task":"Rewrite it with verbs doing the work, in half the words.","tips":["Turn 'reduction in utilization' into 'the facilities are underused'.","Let verbs carry the action, not noun phrases.","Cut 'there is', 'due to the fact that'."],"focus":["concision","clarity"],"placeholder":"Northeast facilities sit idle as demand falls."},
    {"id":"concise-con-early-03","level":"early","profession":"consultant","title":"The meta-commentary opener","scenario":"Your email starts: \"I wanted to reach out to give you a quick update and share some thoughts on where things stand with the pricing work.\" That whole sentence says nothing.","task":"Delete the meta-opener and start with the actual news in one line.","tips":["'I wanted to reach out to' is throat-clearing — cut it.","Start where the content starts.","The reader knows it's an update; don't announce it."],"focus":["concision","impact"]},
    {"id":"concise-con-early-04","level":"early","profession":"consultant","title":"The redundant pairs","scenario":"Your memo is full of doubled phrases: 'each and every,' 'first and foremost,' 'plan and prepare,' 'clear and simple.' They pad the line without adding meaning.","task":"Rewrite the memo excerpt keeping only one word from each redundant pair.","tips":["Pick the stronger of the two words and drop the other.","Doubled words signal padding, not emphasis.","Read it aloud — the cut version lands harder."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-05","level":"early","profession":"consultant","title":"The 80-word paragraph","scenario":"Your executive summary has an 80-word paragraph explaining the market decline. The EM told you it needs to be under 40 and still say everything essential.","task":"Cut the paragraph to under 40 words without losing a real point.","tips":["Delete every word that survives its own removal.","Combine sentences that repeat a subject.","Keep the numbers; cut the connective tissue around them."],"focus":["concision","precision"]},
    {"id":"concise-con-early-06","level":"early","profession":"consultant","title":"The filler-laden Slack message","scenario":"Your Slack to the EM: \"Just wanted to quickly check in and see if you maybe had a chance to look at the deck at all, no rush obviously whenever works.\" The ask drowns in softeners.","task":"Rewrite it as one direct, still-polite line.","tips":["Cut 'just', 'quickly', 'maybe', 'at all', 'obviously'.","Politeness survives without the filler.","Give a real timeframe instead of 'no rush'."],"focus":["concision","clarity"],"placeholder":"Have you had a chance to review the deck? I need it by 3 for the client send."},
    {"id":"concise-con-early-07","level":"early","profession":"consultant","title":"The bullet that's a paragraph","scenario":"One of your slide bullets runs three lines and contains two separate ideas joined by 'and also.' On a slide, that's a paragraph masquerading as a bullet.","task":"Split and trim it into two crisp bullets of under 10 words each.","tips":["One idea per bullet.","Cut articles and helper verbs where the meaning survives.","If it wraps to a second line, it's too long for a slide."],"focus":["concision","structure"]},
    {"id":"concise-con-early-08","level":"early","profession":"consultant","title":"The over-qualified recommendation","scenario":"You wrote: \"It might be worth considering the possibility of potentially exploring an exit from this segment at some point.\" Four hedges stacked on one idea.","task":"Rewrite it as a clear recommendation in one sentence.","tips":["Stack of hedges = no recommendation at all.","State the recommendation; put real uncertainty in a separate caveat.","'Consider exiting' if you mean maybe; 'exit' if you mean it."],"focus":["concision","impact"],"placeholder":"We should exit this segment."},
    {"id":"concise-con-early-09","level":"early","profession":"consultant","title":"The wordy data request","scenario":"Your request to the client runs a paragraph: \"If it wouldn't be too much trouble, I was wondering whether it might be possible for you to potentially share…\" The actual ask is one line.","task":"Rewrite it to a single polite, specific sentence.","tips":["The politeness is in 'please' and 'thanks', not in throat-clearing.","Name the file and date; delete the apologetic wind-up.","Shorter reads as more confident and gets answered faster."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-10","level":"early","profession":"consultant","title":"The 'in order to' habit","scenario":"Your method note is peppered with 'in order to,' 'for the purpose of,' 'in the event that,' 'with regard to.' Each is a three-word phrase where one word works.","task":"Rewrite the note replacing each bloated phrase with a single word.","tips":["'in order to' → 'to'; 'in the event that' → 'if'.","'with regard to' → 'on' or 'about'.","These phrases add syllables, not meaning."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-11","level":"early","profession":"consultant","title":"The caveat that swallows the point","scenario":"Your finding is buried under three sentences of caveats before you ever state it: sample size, date range, definitional notes. By the time the point arrives, the reader has forgotten what it's about.","task":"Rewrite so the finding comes first in one line and the caveats collapse to one clause.","tips":["Lead with the finding; caveats follow, compressed.","Fold three caveats into one: 'in the top three regions, this quarter'.","A caveat should qualify the point, not hide it."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-12","level":"early","profession":"consultant","title":"The repeated subject","scenario":"Your paragraph starts three consecutive sentences with 'The client's procurement team...' The repetition pads the text and dulls it.","task":"Rewrite the paragraph combining the sentences and cutting the repetition.","tips":["Say the subject once, then use pronouns or restructure.","Combine short sentences that share a subject.","Variety of sentence length keeps the reader moving."],"focus":["concision","structure"]},
    {"id":"concise-con-early-13","level":"early","profession":"consultant","title":"The over-built email sign-off","scenario":"Your email ends: \"Please don't hesitate to reach out if you have any questions or concerns whatsoever, and I'd be more than happy to discuss further at your earliest convenience.\" It's boilerplate.","task":"Replace it with one short, human sign-off line.","tips":["'Questions? Happy to talk.' does the whole job.","Boilerplate closers signal you stopped thinking.","Match the length of the close to the length of the message."],"focus":["concision","audience"]},
    {"id":"concise-con-early-14","level":"early","profession":"consultant","title":"The verbose exhibit call-out","scenario":"Your chart annotation reads: \"As can be seen in the exhibit above, it is evident that there appears to be a notable upward trend in customer complaints over the period in question.\" That's 30 words to say complaints rose.","task":"Rewrite the call-out to under 8 words.","tips":["Cut 'as can be seen', 'it is evident', 'in question'.","The chart shows the trend; the words state the point.","State the number if you can: 'Complaints doubled since Q1.'"],"focus":["concision","precision"],"placeholder":"Complaints rose 40% over the quarter."},
    {"id":"concise-con-early-15","level":"early","profession":"consultant","title":"The three sentences that are one","scenario":"You wrote: \"The data was incomplete. This was because the client only sent part of the file. As a result, we had to make some assumptions.\" Three short sentences chained by connectors that could be one.","task":"Combine them into one tight sentence.","tips":["Chained short sentences often want to be one.","Cut 'this was because', 'as a result'.","Subordinate the cause instead of narrating it step by step."],"focus":["concision","structure"],"placeholder":"With only a partial file from the client, we had to assume the rest."},
    {"id":"concise-con-early-16","level":"early","profession":"consultant","title":"The padded interview quote intro","scenario":"Before a customer quote in your readout, you wrote four lines of setup explaining who the person is, when you spoke, and why it matters — before the quote that speaks for itself.","task":"Cut the setup to a single attributive clause and let the quote lead.","tips":["'One plant manager put it bluntly:' is enough setup.","A strong quote needs no run-up.","Move any needed context after the quote, briefly."],"focus":["concision","impact"]},
    {"id":"concise-con-early-17","level":"early","profession":"consultant","title":"The over-explained obvious","scenario":"Your note spends two sentences explaining that Q4 has three months and why that matters for annualizing. Your audience is a finance director. You're explaining what they teach interns.","task":"Cut the over-explanation and state only what's non-obvious.","tips":["Respect the reader's knowledge — don't explain the basics.","Keep only the step they couldn't do themselves.","Over-explaining reads as condescending and wastes their time."],"focus":["concision","audience"]},
    {"id":"concise-con-early-18","level":"early","profession":"consultant","title":"The list with three ways to say 'important'","scenario":"Your risk slide calls three different risks 'critical,' 'crucial,' and 'vital.' The synonyms flatten the ranking — everything sounds like a top priority.","task":"Rewrite so priority comes from order and one clear label, not stacked synonyms.","tips":["Rank by position, not by escalating adjectives.","Reserve 'critical' for the one that truly is.","If everything is critical, nothing is."],"focus":["concision","precision"]},
    {"id":"concise-con-early-19","level":"early","profession":"consultant","title":"The throat-clearing before the question","scenario":"Your message to the senior associate runs two sentences of 'I've been thinking about this and wanted to get your perspective because I know you've seen a lot of these' before the actual question.","task":"Cut the preamble and lead with the question.","tips":["The flattery-preamble delays the ask and reads as filler.","Ask first; add one line of context only if needed.","A good question is a compliment on its own."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-20","level":"early","profession":"consultant","title":"The double-negative fix","scenario":"You wrote: \"It's not unlikely that the client won't disagree with the recommendation.\" The reader has to unpack three negatives to figure out what you mean.","task":"Rewrite it as a plain positive statement.","tips":["Count the negatives — three means rewrite.","State what will happen, not what won't not happen.","Positive phrasing is shorter and clearer."],"focus":["concision","clarity"],"placeholder":"The client will likely accept the recommendation."},
    {"id":"concise-con-early-21","level":"early","profession":"consultant","title":"The bloated title slide subtitle","scenario":"Your section divider's subtitle is a 25-word sentence trying to summarize the whole section. It's too long to read as a divider and too vague to be a headline.","task":"Cut it to a punchy 6-8 word phrase.","tips":["A divider subtitle is a label, not a summary.","Keep the noun that matters; drop the rest.","If it needs a comma, it's probably too long."],"focus":["concision","impact"]},
    {"id":"concise-con-early-22","level":"early","profession":"consultant","title":"The over-worded action item","scenario":"Your action item reads: \"Someone from the team should probably at some point look into whether we might want to reach out to the vendor about pricing.\" No owner, no date, no clear action.","task":"Rewrite it as a crisp action with owner and date.","tips":["Cut the hedges; an action item is a commitment.","Name the owner and the date — that's the whole job.","'Ask the vendor for pricing by Friday — Priya.'"],"focus":["concision","precision"],"placeholder":"Priya: get vendor pricing by Friday."},
    {"id":"concise-con-early-23","level":"early","profession":"consultant","title":"The redundant recap","scenario":"Your email's second paragraph restates the first in different words 'to be clear.' The recap adds length without adding information.","task":"Delete the redundant recap and keep only the strongest phrasing.","tips":["Say it once, well.","'To be clear' usually precedes a repeat, not a clarification.","If the first version needed clarifying, fix it — don't append."],"focus":["concision","clarity"]},
    {"id":"concise-con-early-24","level":"early","profession":"consultant","title":"The verbose 'next steps'","scenario":"Your next-steps section has five items, each written as a full explanatory sentence with rationale baked in. It reads like prose when it should scan like a checklist.","task":"Rewrite the five as scannable action lines, rationale stripped.","tips":["Next steps are for doing, not for justifying.","Verb-first, owner, date — no rationale.","Move the 'why' up into the body if it matters."],"focus":["concision","structure"]},
    {"id":"concise-con-early-25","level":"early","profession":"consultant","title":"Halve the pre-read cover note","scenario":"Your pre-read cover note is a full page. The EM says attendees won't read a page — get it to a third and keep only what they must know before the room.","task":"Cut the cover note to three lines: what to read, the decision, reading time.","tips":["A cover note orients; it doesn't re-argue the deck.","Three lines: the one decision, the three key pages, the time.","Every cut line is one the reader thanks you for."],"focus":["concision","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-con-early-01","level":"early","profession":"consultant","title":"Vague intensifiers to numbers","scenario":"Your slide note says the client's costs are 'significantly higher' than peers and margins are 'much lower.' The partner will ask 'how much?' before you finish the sentence.","task":"Rewrite the two claims with specific numbers.","tips":["Replace 'significantly' with the actual gap.","'Much lower' → 'four points below the median'.","If you don't have the number, that's a gap to close, not to paper over."],"focus":["precision","impact"],"placeholder":"Costs run 18% above peers; margins sit 4 points below the median."},
    {"id":"precision-con-early-02","level":"early","profession":"consultant","title":"The 'recently' trap","scenario":"Your memo says the client 'recently' lost share and 'a while ago' changed their pricing. The EM needs dates to build the timeline that explains cause and effect.","task":"Rewrite both time references as specific dates or periods.","tips":["'Recently' means nothing to a reader building a timeline.","Give the quarter or month.","Precise dates let the reader test your cause-and-effect."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-03","level":"early","profession":"consultant","title":"From data to one insight","scenario":"Your exhibit has a table of monthly sales for 24 months across four regions. It's accurate but says nothing on its own. The team needs the one insight the table supports.","task":"Write the single-sentence insight the table proves, with the number that anchors it.","tips":["A table is evidence; the insight is what it proves.","Find the one pattern that matters and state it.","Anchor with the decisive number, not all of them."],"focus":["precision","impact"],"placeholder":"Northeast sales fell 22% while the other three regions held flat."},
    {"id":"precision-con-early-04","level":"early","profession":"consultant","title":"The unsourced claim","scenario":"You wrote 'the market is growing fast.' The senior associate circled it and wrote 'source? how fast?' You have the number in your research but didn't cite it.","task":"Rewrite the claim with the figure and its source.","tips":["Every quantitative claim needs a number and a source.","'Growing fast' → 'growing 12% a year (industry report, 2025)'.","A cited claim survives the skeptic; a vague one doesn't."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-05","level":"early","profession":"consultant","title":"What / So what / Now what","scenario":"Your finding stops at the 'what': the client's top five customers account for 70% of revenue. The team needs you to carry it through to the implication and the move.","task":"Write three sentences: the fact, what it means, what to do.","tips":["What: the fact, stated cleanly.","So what: the risk or opportunity it creates.","Now what: the concrete next move it implies."],"focus":["precision","impact"],"placeholder":"Five customers drive 70% of revenue. That's a concentration risk if any one leaves. We should…"},
    {"id":"precision-con-early-06","level":"early","profession":"consultant","title":"The skeptic test","scenario":"You claim consolidating two DCs saves $3M. A skeptical CFO will ask: over what period, net of what costs, versus what baseline? Your current line answers none of that.","task":"Rewrite the claim so it survives all three skeptic questions.","tips":["State the period, the baseline, and whether it's net.","'$3M gross over year one' beats a bare '$3M'.","Pre-answer the challenge inside the claim."],"focus":["precision","impact"]},
    {"id":"precision-con-early-07","level":"early","profession":"consultant","title":"The rounded-away precision","scenario":"You wrote 'about half of customers are unhappy.' The real number is 43%, and it matters because the client's threshold for action is 40%. Rounding to 'half' loses the point.","task":"Rewrite with the exact figure and note why the precision matters here.","tips":["Round only when the exact number doesn't change the decision.","43% vs. the 40% threshold is a finding; 'about half' isn't.","Precision is respect for a reader who will act on it."],"focus":["precision","impact"]},
    {"id":"precision-con-early-08","level":"early","profession":"consultant","title":"The apples-to-oranges comparison","scenario":"Your benchmark compares the client's 2023 full-year cost to a competitor's 2024 half-year cost. The numbers look damning but the comparison isn't clean, and a sharp reader will catch it.","task":"Rewrite the comparison so both sides are on the same basis, and state the basis.","tips":["Name the basis: same period, same scope, same currency.","An unclean comparison is worse than none — it invites a rebuttal.","If you must approximate, say so and bound the error."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-09","level":"early","profession":"consultant","title":"The confidence you don't have","scenario":"Your interview synthesis states 'customers prefer the premium tier' as fact. It came from three of eight interviews. Stating it flat overclaims what eight conversations can prove.","task":"Rewrite the claim to match the actual strength of evidence.","tips":["Match the claim's confidence to the evidence behind it.","'Three of eight we spoke with' is honest and still useful.","Overclaiming costs you credibility when the survey disagrees."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-10","level":"early","profession":"consultant","title":"The vague magnitude in the ask","scenario":"You're asking the client for 'a lot of' transaction data over 'a good chunk of' last year. They can't scope the pull without exact fields and dates.","task":"Rewrite the request with exact fields, granularity, and date range.","tips":["Vague scope gets a vague, slow response.","Name the fields, the grain (daily/weekly), the exact date range.","Precise requests are easier to say yes to."],"focus":["precision","clarity"],"placeholder":"Daily transaction records, SKU-level, Jan 1–Dec 31 2024, with these five fields:"},
    {"id":"precision-con-early-11","level":"early","profession":"consultant","title":"The 'improved' with no baseline","scenario":"Your page says the client's delivery times 'improved' after the pilot. Improved from what, to what, over how long? Without the baseline, 'improved' is unfalsifiable and unpersuasive.","task":"Rewrite with the before, the after, and the timeframe.","tips":["A change needs a from and a to.","'From 4 days to 2.5 over the 3-month pilot' is a claim.","No baseline means no credible improvement."],"focus":["precision","impact"]},
    {"id":"precision-con-early-12","level":"early","profession":"consultant","title":"The assumption stated as fact","scenario":"Your model output says the client will save $5M. That rests on an assumed 15% adoption rate you invented for the base case. The slide presents it as if it were measured.","task":"Rewrite so the assumption is visible and labeled, not hidden inside a fact.","tips":["Separate what you measured from what you assumed.","Surface the driving assumption: 'assuming 15% adoption'.","Let the reader test the assumption rather than swallow the output."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-13","level":"early","profession":"consultant","title":"The qualitative claim that needs a number","scenario":"Your readout says the client's onboarding is 'slow and frustrating.' A skeptic asks how slow. You have the data — median onboarding takes 11 days versus a 3-day industry norm — but the slide only has adjectives.","task":"Rewrite the claim leading with the number, adjectives second.","tips":["Lead with the measurable gap, then the human color.","'11 days vs. a 3-day norm' does the persuading.","Adjectives support numbers; they don't replace them."],"focus":["precision","impact"],"placeholder":"Onboarding takes 11 days against a 3-day industry norm —"},
    {"id":"precision-con-early-14","level":"early","profession":"consultant","title":"The precise-sounding but empty phrase","scenario":"Your slide says results were 'directionally consistent with a meaningful uplift across key metrics.' It sounds analytical but names no metric, no direction, no size.","task":"Rewrite it naming the metric, the direction, and the magnitude.","tips":["'Directionally consistent' is a hedge dressed as rigor.","Name the actual metric and how much it moved.","If you can't fill in the numbers, you don't have the finding yet."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-15","level":"early","profession":"consultant","title":"The sample you didn't disclose","scenario":"Your survey slide reports '68% prefer option A.' You didn't say n=25. The team is about to put it in front of the client as if it were robust, and someone will ask the sample size.","task":"Rewrite the finding to include the sample and what it can support.","tips":["Always disclose n on a survey claim.","Say what the sample can and can't support.","Better you flag the limit than the client does."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-16","level":"early","profession":"consultant","title":"The causal leap","scenario":"Your slide implies the client's new pricing 'caused' the revenue jump. But the jump coincided with a competitor's stockout. You have correlation, not proven cause, and the headline overreaches.","task":"Rewrite the claim to state what the data actually supports.","tips":["Correlation isn't cause — say what you can defend.","Name the confound: the competitor stockout.","'Revenue rose alongside the pricing change' is honest."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-17","level":"early","profession":"consultant","title":"The range that's really a guess","scenario":"You wrote the savings are '$2-8M.' That range is so wide it's a shrug. The EM needs to know what drives the spread and where your best estimate sits.","task":"Rewrite giving a best estimate and naming what drives the range.","tips":["A 4x range signals you haven't pinned the driver.","Give a point estimate and the swing factor.","'~$4M, ranging $2-8M depending on adoption' is useful."],"focus":["precision","impact"],"placeholder":"Best estimate ~$4M; the range ($2-8M) hinges on adoption rate."},
    {"id":"precision-con-early-18","level":"early","profession":"consultant","title":"The undated status number","scenario":"Your tracker says '60% complete.' Complete as of when, measured how? The EM saw 60% last week too and wants to know if it moved.","task":"Rewrite the status with a date, a definition, and the trajectory.","tips":["A percentage needs an as-of date to mean anything.","Define what 100% is — otherwise 60% is arbitrary.","Note the delta since last check."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-19","level":"early","profession":"consultant","title":"The 'best practice' with no evidence","scenario":"Your recommendation cites 'industry best practice' with no example. The client's team will ask 'whose practice, and did it work for them?' You have two named cases — use them.","task":"Rewrite the claim grounding it in the two specific cases.","tips":["'Best practice' is empty until you name who did it.","Cite the companies and what they got.","One concrete example beats the phrase 'best practice'."],"focus":["precision","impact"]},
    {"id":"precision-con-early-20","level":"early","profession":"consultant","title":"The insight lost in decimals","scenario":"Your exhibit reports growth as '12.734%.' The false precision distracts from the point and implies a certainty the data doesn't have. But rounding to '13%' is right here.","task":"Rewrite the figure at appropriate precision and state why.","tips":["Match decimal places to the data's real precision.","Two decimals on a modeled estimate is fake rigor.","Round to what the reader can act on: '~13%'."],"focus":["precision","clarity"]},
    {"id":"precision-con-early-21","level":"early","profession":"consultant","title":"The 'stakeholders said' aggregation","scenario":"Your readout says 'stakeholders raised concerns about the timeline.' Which stakeholders, how many, how strongly? Aggregating hides whether it's one loud voice or a consensus.","task":"Rewrite specifying who, how many, and how strongly.","tips":["'Stakeholders' hides the count and the weight.","'Four of six, including the sponsor' changes the meaning.","Name where the concern is loudest."],"focus":["precision","audience"]},
    {"id":"precision-con-early-22","level":"early","profession":"consultant","title":"The estimate presented as measured","scenario":"Your cost figure of $4.2M is a modeled estimate, but the slide shows it to the dollar like it's an invoice. The precision implies a certainty you don't have.","task":"Rewrite so the figure reads as an estimate, at honest precision.","tips":["Signal 'estimate' with a tilde or 'approximately'.","Round to the precision the model actually supports.","False precision invites false confidence — and a fall when it's wrong."],"focus":["precision","clarity"],"placeholder":"~$4M (modeled estimate)"},
    {"id":"precision-con-early-23","level":"early","profession":"consultant","title":"The comparison without a denominator","scenario":"Your slide says the client had '340 complaints' last quarter — up from 210. But you never say out of how many transactions, so the reader can't tell if that's a crisis or noise.","task":"Rewrite the claim with the rate, not just the count.","tips":["Raw counts mislead without a denominator.","'340 complaints per 100k orders, up from 210' anchors it.","A rate lets the reader judge; a count just alarms."],"focus":["precision","impact"]},
    {"id":"precision-con-early-24","level":"early","profession":"consultant","title":"The insight the exhibit doesn't show","scenario":"Your headline claims 'costs are driven by labor,' but the exhibit below is a pie of all cost categories that doesn't isolate labor's trend. The evidence doesn't match the claim.","task":"Rewrite the headline to match what the exhibit actually proves, or state what exhibit you'd need.","tips":["The headline must be provable from the exhibit under it.","If they don't match, fix the weaker one.","A claim the chart doesn't support is a credibility risk."],"focus":["precision","structure"]},
    {"id":"precision-con-early-25","level":"early","profession":"consultant","title":"The 'we believe' with no basis","scenario":"Your recommendation says 'we believe the client can capture 20% of the new segment.' Believe based on what? The partner will want the analogue, the assumption, or the bottom-up build behind the 20%.","task":"Rewrite so the 20% is grounded in a stated basis.","tips":["'We believe' is a promise you must back.","Name the analogue or the build: 'based on X's entry, adjusted for…'.","A number with a basis is a case; without one it's a wish."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-con-early-01","level":"early","profession":"consultant","title":"The neutral menu, owned","scenario":"The EM asks which of two survey approaches to use. Your draft lays out both evenhandedly and stops, leaving the EM to decide with no steer. You actually have a view.","task":"Rewrite so you recommend one and give the two reasons, while still noting the tradeoff.","tips":["A recommendation with a reason beats a balanced menu.","'I'd go with A because X and Y' shows judgment.","Note the tradeoff you're accepting — that's not weakness, it's clarity."],"focus":["impact","clarity"],"placeholder":"I'd use the online panel — faster and cheaper, at the cost of some depth."},
    {"id":"presence-con-early-02","level":"early","profession":"consultant","title":"Fact vs. judgment, separated","scenario":"In your update you blend 'the model shows $3M in savings' (fact) with 'so we should definitely pursue this' (judgment) as if they carried equal certainty. The EM can't tell where the data ends and your opinion begins.","task":"Rewrite so the fact and your judgment are clearly distinguished.","tips":["Label the line between what the data says and what you conclude.","'The model shows X; my read is Y' keeps them honest.","A reader trusts you more when you show the seam."],"focus":["impact","precision"]},
    {"id":"presence-con-early-03","level":"early","profession":"consultant","title":"Signposting the update","scenario":"Your verbal update to the EM wanders with no map. You want the EM to know it has three parts and a request, so nothing gets lost and you sound in command of the material.","task":"Write the signposted opening and the one-line transitions between parts.","tips":["Announce the structure: 'status, one risk, one ask.'","Signpost each turn: 'first…', 'the risk is…', 'what I need…'.","Signposting reads as control, not verbosity."],"focus":["structure","impact"]},
    {"id":"presence-con-early-04","level":"early","profession":"consultant","title":"Owning the number under scrutiny","scenario":"In the team meeting the senior associate questions your $4M estimate. Your instinct is to get defensive or immediately fold. Presence means standing behind your work while staying open.","task":"Write a 2-3 sentence response that owns the number and invites the specific challenge.","tips":["State your confidence and its basis, calmly.","Invite the specific objection rather than defending everything.","'Here's what would change it' shows range, not weakness."],"focus":["impact","precision"],"placeholder":"I'm confident in the $4M for the base case — here's the assumption it hinges on, and where I'd want your challenge."},
    {"id":"presence-con-early-05","level":"early","profession":"consultant","title":"The recommendation you'd stake your name on","scenario":"You've analyzed three options and prefer one, but your slide reads like a Wikipedia summary of all three — no voice, no stance. The partner wants to know what YOU think.","task":"Rewrite the slide to lead with a clear recommendation you'd defend.","tips":["Take a position; the analysis earned you the right.","'We recommend X' with the case, not 'here are three options'.","Options-only reads as junior; a recommendation reads as senior."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-06","level":"early","profession":"consultant","title":"Speaking up in the partner review","scenario":"The partner is reviewing your workstream and says something about the data that you know is slightly wrong. Staying silent protects your comfort; presence means correcting respectfully in the moment.","task":"Write the one respectful sentence that corrects the record.","tips":["Correct the fact, not the person.","'One clarification —' opens the door without confrontation.","Silence on a known error costs you more later."],"focus":["impact","audience"]},
    {"id":"presence-con-early-07","level":"early","profession":"consultant","title":"The confident caveat","scenario":"Your finding is solid but has one real limitation. You can present it apologetically ('sorry, the data's not perfect') or with presence ('here's what it shows and the one boundary'). The content is identical; the framing changes how it lands.","task":"Write the finding-plus-caveat framed with confidence, not apology.","tips":["State the finding first, plainly.","Frame the limit as a boundary you understand, not a failure.","'Solid within the top three regions' beats 'sorry, only three regions'."],"focus":["impact","precision"]},
    {"id":"presence-con-early-08","level":"early","profession":"consultant","title":"The stance in the storyline","scenario":"Your section titles all hedge: 'potential opportunity,' 'possible risk,' 'may suggest.' Read together they sound like the deck is afraid of its own conclusions. The senior associate wants conviction.","task":"Rewrite three hedged titles into confident, defensible statements.","tips":["Replace 'may suggest' with what it shows.","Confidence you can defend reads as presence; hedging reads as fear.","Keep honesty — be confident about what's true, not about everything."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-09","level":"early","profession":"consultant","title":"The 'I don't know' with a path","scenario":"In the client meeting a manager asks you a question outside your analysis. You don't know the answer. Presence isn't bluffing — it's a clean 'I don't know' with a commitment.","task":"Write the 2-sentence response that admits the gap and commits to a path.","tips":["Say you don't know, plainly — no waffle.","Commit to when and how you'll get the answer.","A confident 'I'll find out by Thursday' builds more trust than a bluff."],"focus":["impact","audience"],"placeholder":"I don't have that in front of me — I'll confirm the exact figure and send it by end of day."},
    {"id":"presence-con-early-10","level":"early","profession":"consultant","title":"The recommendation register","scenario":"Your recommendation email to the EM is written in tentative student voice: 'I was thinking maybe we could possibly consider...' It undersells solid analysis. The register needs to match the quality of the work.","task":"Rewrite it in a register that owns the recommendation.","tips":["Match your voice to the strength of your evidence.","'I recommend' when you've done the work to recommend.","Tentative voice makes good analysis sound like a guess."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-11","level":"early","profession":"consultant","title":"Presenting your own slide","scenario":"You're about to walk the team through a page you built. You could apologize for it ('this is rough, but...') or present it with ownership. The apology primes everyone to find fault.","task":"Write the confident one-line intro to your slide.","tips":["Don't pre-apologize — it invites criticism you haven't earned.","Lead with what the page shows and why it matters.","If it's genuinely draft, say 'draft' once, then present it straight."],"focus":["impact","audience"]},
    {"id":"presence-con-early-12","level":"early","profession":"consultant","title":"The judgment call, labeled","scenario":"You made a modeling choice — using median instead of mean — that materially affects the result. You could bury it or own it. Presence means flagging it as your judgment and defending it.","task":"Write the 2-sentence note that owns the choice and its reason.","tips":["Name the choice as yours: 'I chose median because…'.","Give the reason a skeptic would accept.","Owning a judgment call is stronger than hiding it and being caught."],"focus":["impact","precision"]},
    {"id":"presence-con-early-13","level":"early","profession":"consultant","title":"The disagreement with the senior associate","scenario":"The senior associate wants to drop a finding you think is central. You can defer silently or make your case with presence. This is your workstream — you have standing to argue for it.","task":"Write a 3-sentence case for keeping the finding, respectfully but firmly.","tips":["State your position first, then the reasoning.","Acknowledge their concern without abandoning your view.","'I'd push to keep it, because…' is presence, not insubordination."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-14","level":"early","profession":"consultant","title":"The steering committee soundbite","scenario":"You've been asked to deliver one finding at the steering committee — 90 seconds. Junior instinct is to cram in every caveat. Presence is one clear message, delivered with conviction, held to time.","task":"Write the 90-second finding as it should be spoken: message, evidence, implication.","tips":["One message, stated with conviction.","One piece of evidence, one implication — no caveat pile.","Steerco remembers the message, not the footnotes."],"focus":["impact","structure"],"placeholder":"The headline is simple: two-thirds of churn comes from service, not price."},
    {"id":"presence-con-early-15","level":"early","profession":"consultant","title":"The credit and the stance","scenario":"You're presenting analysis the whole team contributed to, but you're the one in the room. You want to credit the team without diffusing your own ownership of the recommendation you're making.","task":"Write the opening that credits the team and owns the recommendation.","tips":["'The team built this; my recommendation is —' does both.","Credit generously, then take your stance.","Diffusing ownership entirely reads as hiding from the call."],"focus":["impact","audience"]},
    {"id":"presence-con-early-16","level":"early","profession":"consultant","title":"The pushback you saw coming","scenario":"You know the client's ops lead will resist your finding because it implicates his team. Presence means naming that dynamic calmly rather than being blindsided when he pushes.","task":"Write how you'd open the finding to that audience, acknowledging the tension without flinching.","tips":["Name the tension before he does.","Frame it as shared problem-solving, not blame.","Confidence here is staying steady when the pushback lands."],"focus":["impact","audience"]},
    {"id":"presence-con-early-17","level":"early","profession":"consultant","title":"From 'the data suggests' to a verdict","scenario":"Your whole slide is written in passive, agentless voice: 'it is suggested that,' 'the data indicates a possibility.' No one owns the conclusion. The partner wants a person behind the point.","task":"Rewrite the key line so a clear subject owns the verdict.","tips":["Give the sentence a subject: 'we recommend', 'the data shows'.","Passive voice hides accountability — presence claims it.","Own the verdict; the analysis backs you."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-18","level":"early","profession":"consultant","title":"The composed answer to a curveball","scenario":"In the client session someone challenges your entire approach in front of the room. Your pulse spikes. Presence is a composed, structured reply — not a flustered defense or a collapse.","task":"Write a calm 3-sentence reply that acknowledges, reframes, and stands ground.","tips":["Acknowledge the point without agreeing reflexively.","Reframe to what the analysis actually claims.","Composure is the message here as much as the words."],"focus":["impact","audience"],"placeholder":"That's a fair challenge. What we're claiming is narrower than it may have sounded —"},
    {"id":"presence-con-early-19","level":"early","profession":"consultant","title":"The recommendation with skin in it","scenario":"Your EM asks 'if it were your money, what would you do?' Your draft dodges into 'it depends.' Presence is giving a real answer with a real reason, then noting the condition.","task":"Answer the question directly, then state the one condition that would change it.","tips":["Answer the question they asked, not a safer one.","'I'd do X' then 'unless Y', in that order.","'It depends' without saying on what is a non-answer."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-20","level":"early","profession":"consultant","title":"The one-line stance in the doc","scenario":"The team problem-solving doc asks each analyst for a point of view on the central question. Others wrote paragraphs of on-the-one-hand. You want to state a clear position that starts the debate.","task":"Write your one-line position with the single strongest reason.","tips":["A stated position moves the discussion; fence-sitting stalls it.","One line, one reason — you can defend it in the meeting.","Being wrong and clear beats being vague and safe."],"focus":["impact","clarity"]},
    {"id":"presence-con-early-21","level":"early","profession":"consultant","title":"Delivering the number to the CFO","scenario":"You're presenting the savings figure directly to the client's CFO. You built it, you trust it. Junior instinct is to over-explain the method defensively. Presence is stating the number and letting it stand.","task":"Write the 2-sentence delivery: the number, then what stands behind it in brief.","tips":["State the number with a steady voice.","One line of what backs it — not the full method dump.","Let a strong number sit; over-explaining signals doubt."],"focus":["impact","precision"]},
    {"id":"presence-con-early-22","level":"early","profession":"consultant","title":"The stance under time pressure","scenario":"The EM needs your read in the next five minutes to brief the partner. There's no time for a memo. Presence is a fast, structured verbal recommendation that the EM can carry up confidently.","task":"Write the 30-second verbal recommendation with headline, reason, and confidence level.","tips":["Headline first: the recommendation in one line.","One reason and your confidence level.","Speed plus structure is the presence move under pressure."],"focus":["impact","structure"],"placeholder":"My read: go with the phased rollout. One reason, and I'm fairly confident —"},
    {"id":"presence-con-early-23","level":"early","profession":"consultant","title":"The room-reading adjustment","scenario":"Mid-update, you notice the EM's attention drifting — you've gone too deep into method. Presence includes reading the room and adjusting live, cutting to the point without visibly floundering.","task":"Write the one-line pivot that gets you back to what the EM cares about.","tips":["Notice the signal and pivot cleanly.","'Let me get to the point —' resets without apology.","Adjusting mid-stream reads as awareness, not failure."],"focus":["impact","audience"]},
    {"id":"presence-con-early-24","level":"early","profession":"consultant","title":"The confident close","scenario":"You've finished walking the team through your analysis. Junior instinct is to trail off ('so, yeah, that's kind of it'). Presence is a clean close that lands the point and names the next step.","task":"Write a 2-sentence close: the takeaway restated, then the next step.","tips":["End on the message, not a mumble.","Restate the one takeaway, then the concrete next step.","A strong close is what the room remembers."],"focus":["impact","structure"]},
    {"id":"presence-con-early-25","level":"early","profession":"consultant","title":"Owning the recommendation in the deck","scenario":"The executive summary of your section presents 'considerations' and lets the reader connect the dots. The partner wants the section to make a recommendation, not lay out a buffet. This is your chance to show judgment on the page.","task":"Rewrite the summary so it leads with a recommendation and marshals the considerations under it.","tips":["Lead with the recommendation; considerations become support.","A buffet asks the reader to do your job.","Judgment on the page is what turns an analyst into an associate."],"focus":["impact","structure"],"placeholder":"We recommend consolidating to three DCs. Three considerations shape this:"}
  ],
  "answering-under-pressure": [
    {"id":"pressure-con-early-01","level":"early","profession":"consultant","title":"Answer the question asked","scenario":"The partner asks: \"Is the Thursday deck going to hold?\" You start explaining the three data pulls still in flight. The partner wanted a yes/no first, then the risk.","task":"Answer the yes/no first, then the one reason, in two sentences.","tips":["Answer the actual question in the first word.","Yes or no, then the single caveat.","Explaining before answering reads as dodging."],"focus":["clarity","impact"],"placeholder":"Yes, Thursday holds — one data pull is the only risk, and I have a fallback."},
    {"id":"pressure-con-early-02","level":"early","profession":"consultant","title":"The 'I don't know' that keeps trust","scenario":"In the client meeting the CFO asks a detail about your model you genuinely don't recall. You feel pressure to invent something plausible. The right move is honesty plus a path.","task":"Write the response: admit the gap, commit to the answer, in two sentences.","tips":["Don't bluff a number in front of a CFO — you'll be caught.","'I don't have that exact figure; I'll confirm by end of day.'","A clean I-don't-know protects every other number you gave."],"focus":["clarity","precision"],"placeholder":"I don't have that number in front of me — I'll send the exact figure this afternoon."},
    {"id":"pressure-con-early-03","level":"early","profession":"consultant","title":"Pushback with specifics, not defense","scenario":"The senior associate says your churn number 'seems too high.' Your instinct is to defend everything at once. Better: ask what seems off, then answer with the specific method point.","task":"Write a 2-3 sentence reply that engages the specific doubt calmly.","tips":["Don't defend the whole analysis — isolate the doubt.","Ask or state the specific point: 'the high number is driven by X'.","Specifics de-escalate; blanket defense escalates."],"focus":["clarity","precision"]},
    {"id":"pressure-con-early-04","level":"early","profession":"consultant","title":"The curveball in the client room","scenario":"You're presenting and the client asks about a region you didn't analyze. Freezing or waffling loses the room. You need a composed answer that's honest about scope and offers value anyway.","task":"Write the 2-sentence response that handles the out-of-scope question with composure.","tips":["Name the scope boundary without apologizing for it.","Offer what you can: a related insight or a next step.","Composure is half the answer here."],"focus":["impact","audience"]},
    {"id":"pressure-con-early-05","level":"early","profession":"consultant","title":"When the EM challenges your assumption","scenario":"The EM says 'your 15% adoption assumption seems optimistic.' They may be right. You need to answer without either caving instantly or digging in — engage the substance.","task":"Write a reply that defends the basis while genuinely testing it, in 2-3 sentences.","tips":["Give the basis for the 15%, then invite the alternative.","'Here's where it came from; what would you use?'","Testing the assumption together beats defending it alone."],"focus":["precision","impact"]},
    {"id":"pressure-con-early-06","level":"early","profession":"consultant","title":"The rapid-fire status grilling","scenario":"The partner fires three questions in a row: when's it done, is the finding solid, what's the risk. You tend to answer the first at length and forget the other two. Presence under pressure is answering all three, crisply.","task":"Write a crisp one-line answer to each of the three questions.","tips":["Answer each question, in order, in one line.","Don't let the first question eat all your airtime.","Signal you heard all three: 'On timing… on the finding… on risk…'."],"focus":["structure","clarity"]},
    {"id":"pressure-con-early-07","level":"early","profession":"consultant","title":"The question you can't answer yet","scenario":"The client asks what the final recommendation will be — but you're mid-analysis and it's genuinely open. You can't fabricate a conclusion, and you can't just say 'don't know.' Give an honest status with a date.","task":"Write a 2-sentence answer that's honest about the open question and commits to when it closes.","tips":["Say it's still open — and why that's the right state right now.","Commit to when you'll have the answer.","'Forming a view; I'll have a recommendation by Friday' is fine."],"focus":["clarity","precision"]},
    {"id":"pressure-con-early-08","level":"early","profession":"consultant","title":"Deflecting the blame question","scenario":"In a tense client meeting, someone asks 'whose fault is the delay?' The honest answer involves the client's late data, but naming that in the room would poison the relationship. Answer the underlying concern, not the blame.","task":"Write a 2-sentence answer that addresses the real concern without assigning blame in the room.","tips":["Reframe from blame to path forward.","'Here's where we are and how we recover the time.'","Save the data-timing conversation for the EM, offline."],"focus":["audience","impact"]},
    {"id":"pressure-con-early-09","level":"early","profession":"consultant","title":"The number they think is wrong","scenario":"The client's finance lead insists your cost figure is wrong — it doesn't match his. Under pressure you might cave or argue. The move is to find where the two numbers diverge, calmly.","task":"Write a 2-3 sentence reply that seeks the source of the discrepancy.","tips":["Don't assert you're right — locate the difference.","'Let's reconcile — mine includes X; does yours?'","Reconciling wins trust; arguing loses it either way."],"focus":["precision","audience"],"placeholder":"Let's reconcile the two — mine includes overhead allocation; I suspect that's the gap."},
    {"id":"pressure-con-early-10","level":"early","profession":"consultant","title":"The senior associate tests your understanding","scenario":"The senior associate asks 'why did you use median here?' It's not an attack — it's a test of whether you understand your own choice. Waffling reveals you copied a template. A clear reason shows you own the work.","task":"Write a 2-sentence answer that gives the real reason for the choice.","tips":["Give the substantive reason, not 'it seemed right'.","'Median because the distribution is skewed by two outliers.'","Owning your method choices is how trust in your work grows."],"focus":["precision","clarity"]},
    {"id":"pressure-con-early-11","level":"early","profession":"consultant","title":"The 'so what does this mean for us' ambush","scenario":"You presented a data slide and the client jumps straight to 'so what does this mean for us?' — the implication you hadn't planned to state yet. You need to answer the real question, not retreat to the data.","task":"Write a 2-sentence answer that gives the implication, honestly bounded.","tips":["Answer the 'so what', don't re-narrate the chart.","Give the implication you can defend; flag what's still forming.","Retreating to the data when asked for meaning reads as dodging."],"focus":["impact","clarity"]},
    {"id":"pressure-con-early-12","level":"early","profession":"consultant","title":"Holding the line on a defensible number","scenario":"A client stakeholder pushes hard for you to soften a finding that reflects badly on his team. The number is right. Under social pressure, you need to hold the finding while staying respectful.","task":"Write a 2-3 sentence reply that holds the finding without escalating.","tips":["Acknowledge the discomfort, hold the number.","'I understand this is hard; the data is consistent across sources.'","Softening a right number to please the room is a trap."],"focus":["impact","precision"]},
    {"id":"pressure-con-early-13","level":"early","profession":"consultant","title":"The interruption mid-answer","scenario":"You're two sentences into answering the partner when they interrupt with a follow-up. You lose your thread. Presence is absorbing the new question and answering it, not stubbornly finishing your first point.","task":"Write how you'd handle it: acknowledge the pivot and answer the new question.","tips":["Follow the partner's lead — answer the live question.","'Good pivot —' then address it.","Rigidly finishing your first point reads as not listening."],"focus":["audience","clarity"]},
    {"id":"pressure-con-early-14","level":"early","profession":"consultant","title":"The 'are you sure?' pressure test","scenario":"You state a finding and the EM just says 'are you sure?' It's a confidence probe. Caving signals the finding was a guess; blustering signals you can't distinguish confidence levels. Give a calibrated answer.","task":"Write a 2-sentence answer that states your confidence and what would change it.","tips":["Give a real confidence level, not reflexive certainty or doubt.","Name what would change your mind — that's rigor.","'Confident on the direction; the exact size could move with X.'"],"focus":["precision","impact"]},
    {"id":"pressure-con-early-15","level":"early","profession":"consultant","title":"The hostile question in the workshop","scenario":"In a client workshop, a skeptical manager asks 'have you people ever actually run a plant?' It's a shot at consultant credibility. You can't win a credentials fight; you can answer with what your analysis brings.","task":"Write a composed 2-sentence reply that acknowledges his point and redirects to value.","tips":["Concede the point graciously — you haven't run his plant.","Redirect to what you do bring: the cross-plant view.","Getting defensive proves his point; composure disarms it."],"focus":["audience","impact"],"placeholder":"You're right that we haven't — that's exactly why we lean on your team's experience, and what we add is the view across all six plants."},
    {"id":"pressure-con-early-16","level":"early","profession":"consultant","title":"The question that reveals a gap","scenario":"The senior associate asks a question that exposes something you should have checked but didn't. Instant panic. The move is to own the gap immediately and state how you'll close it, without excuses.","task":"Write a 2-sentence response that owns the gap and commits to closing it.","tips":["Own it cleanly — no excuses, no burying it.","State the fix and the timing.","Owning a gap fast costs less than being caught hiding it."],"focus":["clarity","impact"]},
    {"id":"pressure-con-early-17","level":"early","profession":"consultant","title":"The tangent that's eating the meeting","scenario":"A client stakeholder keeps pulling the discussion into a detail that doesn't matter to today's decision. As the analyst presenting, you need to answer briefly and steer back, without seeming to dismiss him.","task":"Write the 2-sentence move: acknowledge the point, park it, return to the agenda.","tips":["Acknowledge so he feels heard.","Park it: 'let's take that offline / into the appendix'.","Return to the decision the meeting exists to make."],"focus":["structure","audience"]},
    {"id":"pressure-con-early-18","level":"early","profession":"consultant","title":"The 'give me a number now' demand","scenario":"The partner wants a rough sizing on the spot, before your analysis is done. You could refuse ('not ready') or guess wildly. The move is a bounded estimate with the caveat, delivered fast.","task":"Write a 2-sentence answer: a bounded estimate plus what would firm it up.","tips":["Give a range with your basis, not a refusal.","'Order of magnitude, X — I'll firm it once the data lands.'","'Not ready' frustrates; a caveated estimate helps."],"focus":["precision","impact"]},
    {"id":"pressure-con-early-19","level":"early","profession":"consultant","title":"The follow-up you didn't expect","scenario":"You answered the client's question well, then they ask 'and what would it cost to fix?' — which you haven't costed. Don't invent a number; give the honest state and the path to it.","task":"Write a 2-sentence reply that's honest about not having costed it yet and commits to a follow-up.","tips":["Don't guess a cost in the room.","Say when you'll have it and what it depends on.","A committed follow-up beats a fabricated figure."],"focus":["clarity","precision"]},
    {"id":"pressure-con-early-20","level":"early","profession":"consultant","title":"The two-part question, half-answered","scenario":"The EM asks 'is it done, and can I send it to the client?' You answer 'it's done' and stop, forgetting the second half. Under pressure you drop the part that actually mattered.","task":"Write the answer that addresses both halves clearly.","tips":["Track both parts of a compound question.","Answer each explicitly: 'Done — but hold the send until X.'","The forgotten half is often the one they needed."],"focus":["structure","clarity"]},
    {"id":"pressure-con-early-21","level":"early","profession":"consultant","title":"Staying calm when corrected publicly","scenario":"In the team meeting the partner points out an error in your slide in front of everyone. Your face flushes. Presence is a composed acknowledgment and fix-commitment, not defensiveness or visible collapse.","task":"Write the 2-sentence composed response to a public correction.","tips":["Thank them for the catch — genuinely.","State the fix and when it's done.","Composure under public correction earns more than the error cost."],"focus":["impact","audience"],"placeholder":"Good catch — you're right. I'll correct it and re-send the page within the hour."},
    {"id":"pressure-con-early-22","level":"early","profession":"consultant","title":"The 'why should we believe you' moment","scenario":"A client executive challenges the whole basis of your recommendation. It's a credibility moment. You answer not by asserting authority but by walking to the strongest piece of evidence, calmly.","task":"Write a 2-3 sentence reply that grounds the recommendation in its strongest evidence.","tips":["Don't claim authority — show the evidence.","Lead with the single most convincing fact.","Calm evidence beats a raised voice every time."],"focus":["impact","precision"]},
    {"id":"pressure-con-early-23","level":"early","profession":"consultant","title":"The scope-creep request in the meeting","scenario":"Mid-meeting the client asks you to also analyze a whole new area 'while you're at it.' Saying yes on the spot risks the timeline; a flat no is awkward. Answer honestly about the tradeoff.","task":"Write a 2-sentence reply that neither over-commits nor rejects, and routes it right.","tips":["Don't commit scope in the room — name the tradeoff.","'Happy to — that would push the timeline; let me check with [EM].'","Route scope decisions to where they belong."],"focus":["clarity","audience"]},
    {"id":"pressure-con-early-24","level":"early","profession":"consultant","title":"The confidence question on shaky data","scenario":"The EM asks how solid a finding is, and honestly the data behind it is thin. You're tempted to project confidence you don't have. Under pressure, calibrated honesty is the professional move.","task":"Write a 2-sentence answer that's honest about the data's limits without abandoning the finding.","tips":["Match your stated confidence to the real evidence.","Name the limit and what would strengthen it.","'Directionally solid; I'd want more data before quoting the exact figure.'"],"focus":["precision","clarity"]},
    {"id":"pressure-con-early-25","level":"early","profession":"consultant","title":"The dead-air recovery","scenario":"Mid-presentation, the partner asks a question and your mind goes blank. The silence stretches. Presence is a graceful recovery move — buy a beat, then answer — not a panicked ramble.","task":"Write the recovery line that buys a moment and re-enters the answer cleanly.","tips":["A short pause is fine; fill it deliberately, not with 'um'.","'Let me make sure I answer the right thing —' buys a beat.","Then answer the question, structured."],"focus":["impact","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-con-early-01","level":"early","profession":"consultant","title":"Before and after the change","scenario":"Your recommendation to consolidate suppliers is presented as a static list of benefits. It would land harder as a story: here's the client's world today, here's what it becomes. The contrast is the persuasion.","task":"Write a 3-sentence before/after framing of the recommendation.","tips":["Paint 'today' concretely — the pain the client lives with.","Paint 'after' — the specific better state.","The gap between them is your argument."],"focus":["impact","structure"],"placeholder":"Today, procurement chases 40 suppliers and misses volume discounts. After consolidation…"},
    {"id":"narrative-con-early-02","level":"early","profession":"consultant","title":"Making the stakes concrete","scenario":"Your slide says the client faces 'a competitive threat.' That's abstract. The threat is real — a competitor is undercutting them 15% and taking two accounts a quarter. Concrete stakes persuade; abstract ones get nodded past.","task":"Rewrite the stakes with the specific, concrete threat.","tips":["Replace the abstraction with the real numbers and names.","'Losing two accounts a quarter to a 15% price gap' is vivid.","Concrete stakes make people act; abstractions let them wait."],"focus":["impact","precision"]},
    {"id":"narrative-con-early-03","level":"early","profession":"consultant","title":"Pre-empting the strongest objection","scenario":"Your recommendation to enter a new segment will draw one obvious objection: the client tried it in 2019 and failed. If you don't address it, the room will fixate on it. Name it and answer it before they raise it.","task":"Write the 2-3 sentences that pre-empt the 2019 objection.","tips":["Name the objection yourself — it disarms it.","Explain what's different now, concretely.","Pre-empting shows you did the homework and respects their memory."],"focus":["impact","audience"],"placeholder":"You'll rightly remember the 2019 attempt failed. Two things are different now:"},
    {"id":"narrative-con-early-04","level":"early","profession":"consultant","title":"The finding that needs a why-now","scenario":"Your analysis is sound but the client has no urgency — 'interesting, we'll consider it.' The recommendation needs a why-now: a reason the window is closing or the cost of waiting is rising.","task":"Write the 2-sentence why-now that creates urgency honestly.","tips":["Give a real reason the timing matters — not manufactured panic.","'Each quarter of delay costs X' or 'the window closes when Y'.","Urgency without honesty backfires; find the true clock."],"focus":["impact","precision"]},
    {"id":"narrative-con-early-05","level":"early","profession":"consultant","title":"The customer's voice in the story","scenario":"Your churn finding is all numbers. It would persuade harder with one real customer's words — a quote from your interviews that makes the abstraction human. You have a devastating one.","task":"Write the 2-3 sentence passage that pairs the number with the customer quote.","tips":["Lead with the number, land it with the human voice.","One vivid quote outweighs three more data points.","'The data says 40%; one churned customer put it plainly:'"],"focus":["impact","audience"]},
    {"id":"narrative-con-early-06","level":"early","profession":"consultant","title":"From features to consequences","scenario":"Your recommendation lists what the solution does: 'centralizes procurement, standardizes contracts, adds a spend dashboard.' The client doesn't buy features — they buy consequences. Translate each into what it changes for them.","task":"Rewrite the three features as the consequences the client cares about.","tips":["Every feature becomes a 'so you can' consequence.","'A spend dashboard' → 'you'll catch overspend in days, not quarters'.","Sell the outcome, not the mechanism."],"focus":["impact","audience"]},
    {"id":"narrative-con-early-07","level":"early","profession":"consultant","title":"The arc of the readout","scenario":"Your interview readout is a flat list of themes. It would carry more as an arc: the client's assumption going in, what the interviews revealed, what that means. A narrative arc makes findings stick.","task":"Write the 3-sentence arc: assumption, revelation, implication.","tips":["Start with what everyone assumed was true.","Reveal what the interviews actually showed.","Close on what that changes."],"focus":["structure","impact"],"placeholder":"Going in, we assumed customers left over price. The interviews told a different story:"},
    {"id":"narrative-con-early-08","level":"early","profession":"consultant","title":"The tension the recommendation resolves","scenario":"Your recommendation solves a real tension the client feels — they want growth but fear cannibalizing their core. Naming that tension first makes the recommendation feel like a resolution, not an imposition.","task":"Write the 2-3 sentences that name the tension, then position the recommendation as its resolution.","tips":["Name the bind the client is genuinely in.","Show the recommendation as the way through it.","People accept solutions to tensions they feel, not answers to questions they didn't ask."],"focus":["impact","audience"]},
    {"id":"narrative-con-early-09","level":"early","profession":"consultant","title":"The proof point that persuades","scenario":"You're recommending a move the client is nervous about. You have one strong analogue — a similar company that did it and gained share. That single proof point will do more than another page of your own analysis.","task":"Write the 2-3 sentence passage that deploys the analogue persuasively.","tips":["A relevant analogue reduces perceived risk.","Name the company, the move, the result.","Choose the analogue the client will find credible, not just convenient."],"focus":["impact","precision"]},
    {"id":"narrative-con-early-10","level":"early","profession":"consultant","title":"The cost of doing nothing","scenario":"The client is inclined to defer your recommendation. You haven't made the status-quo option feel costly. The persuasive move is to make 'do nothing' concrete and expensive, not just to praise your option.","task":"Write the 2-3 sentences that make the cost of inaction vivid.","tips":["'Do nothing' is the default — make its cost visible.","Quantify the drift: what erodes each quarter of delay.","People weight losses heavily; show the loss of waiting."],"focus":["impact","precision"]},
    {"id":"narrative-con-early-11","level":"early","profession":"consultant","title":"Framing for the skeptical CFO","scenario":"Your recommendation goes to a CFO who trusts numbers and distrusts consultant narratives. The persuasion has to be framed in his language: payback period, risk, downside protection — not vision.","task":"Write the 2-3 sentence framing pitched at a numbers-first CFO.","tips":["Lead with payback and downside, not upside vision.","Frame it as risk-managed, not aspirational.","Match the narrative to what this decider actually weighs."],"focus":["audience","impact"]},
    {"id":"narrative-con-early-12","level":"early","profession":"consultant","title":"The one-sentence storyline","scenario":"The senior associate asks for the 'storyline' of your section in one sentence. You have twelve pages but no spine. A section that can't be said in one sentence hasn't found its story.","task":"Write the single-sentence storyline that the twelve pages prove.","tips":["If you can't say it in one sentence, the story isn't clear yet.","The sentence should have a subject, a verdict, and a because.","Every page then either supports it or gets cut."],"focus":["structure","impact"]},
    {"id":"narrative-con-early-13","level":"early","profession":"consultant","title":"The objection you're tempted to hide","scenario":"There's a real weakness in your recommendation — the payback is slow. Hiding it feels safer, but the client's advisor will find it and then distrust everything. Naming it first, with your answer, is the persuasive move.","task":"Write the 2-3 sentences that raise the weakness and address it head-on.","tips":["Raise the weakness before the skeptic does.","Pair it with the mitigation or the reframe.","Honesty about the downside makes the upside believable."],"focus":["impact","audience"]},
    {"id":"narrative-con-early-14","level":"early","profession":"consultant","title":"The vivid opening line","scenario":"Your section opens with 'This analysis examines the customer base.' Flat. A vivid opening — a surprising fact or a sharp question — earns the reader's attention for the pages that follow.","task":"Write a vivid one-line opening that hooks the reader into the finding.","tips":["Open with the surprising fact or the sharp stat.","Earn attention in the first line — decks are skimmed.","The hook should point at the finding, not just intrigue."],"focus":["impact","clarity"],"placeholder":"Two-thirds of the customers who left last year never had a single service call."},
    {"id":"narrative-con-early-15","level":"early","profession":"consultant","title":"Persuading the reluctant plant manager","scenario":"Your recommendation asks a plant manager to change a process he's proud of. Pure data won't move him — he'll feel judged. The narrative needs to honor what he built while making the case for change.","task":"Write the 3-sentence framing that respects his work and still argues for the change.","tips":["Credit what works before proposing what changes.","Frame the change as building on his foundation, not fixing his failure.","People defend what they're proud of; enlist that pride."],"focus":["audience","impact"]},
    {"id":"narrative-con-early-16","level":"early","profession":"consultant","title":"The three-act recommendation","scenario":"Your recommendation deck has all the pieces but no shape. A three-act structure — problem, insight, solution — would give the client a journey rather than a data dump. You need the spine.","task":"Write the one-line summary of each act: the problem, the insight, the solution.","tips":["Act one: the problem the client feels.","Act two: the non-obvious insight your analysis found.","Act three: the solution the insight points to."],"focus":["structure","impact"]},
    {"id":"narrative-con-early-17","level":"early","profession":"consultant","title":"The stat that needs a comparison","scenario":"You say the client loses '$8M a year' to the problem. Alone, $8M is just a number. Anchored to something the client feels — 'that's your entire marketing budget' — it becomes persuasive.","task":"Rewrite the stat with a comparison that makes its size felt.","tips":["Anchor big numbers to something the audience knows.","'$8M — the cost of your entire northeast sales team' lands.","Choose a comparison that stings in the right way."],"focus":["impact","precision"]},
    {"id":"narrative-con-early-18","level":"early","profession":"consultant","title":"Handling the 'we already knew that'","scenario":"You anticipate the client saying 'we already knew our costs were high.' Your finding goes further — it locates exactly where and why. The narrative has to acknowledge what they knew and then deliver the new part.","task":"Write the 2-3 sentences that honor their prior knowledge and reveal the new insight.","tips":["Grant what they knew — don't pretend it's news.","Then deliver the sharper, specific finding.","'You knew costs were high; here's the part you couldn't see:'"],"focus":["audience","impact"]},
    {"id":"narrative-con-early-19","level":"early","profession":"consultant","title":"The emotional truth behind the data","scenario":"Your churn data is compelling but bloodless. Behind it is a real story: loyal customers who felt ignored. Surfacing that emotional truth — carefully, without melodrama — makes the client care, not just calculate.","task":"Write the 2-3 sentences that give the data its human meaning.","tips":["Find the human reality the numbers represent.","State it plainly — melodrama undercuts credibility.","'These weren't price-shoppers; they were your most loyal accounts.'"],"focus":["impact","audience"]},
    {"id":"narrative-con-early-20","level":"early","profession":"consultant","title":"The recommendation as the client's idea","scenario":"The client sponsor floated a half-formed version of your recommendation last week. Framing your recommendation as building on her thinking — rather than as your original insight — makes it far easier for her to champion.","task":"Write the 2-3 sentence framing that builds on the sponsor's earlier idea.","tips":["Give the client ownership of the direction where you honestly can.","'Building on what you raised last week —' enlists her.","A recommendation the client feels she shaped gets defended internally."],"focus":["audience","impact"]},
    {"id":"narrative-con-early-21","level":"early","profession":"consultant","title":"The contrast that clarifies","scenario":"Your two options blur together in the reader's mind. A sharp contrast — 'Option A protects margin; Option B chases growth' — clarifies the real choice and makes the recommendation's logic obvious.","task":"Write the one-line contrast that frames the two options as a clear choice.","tips":["Reduce each option to its essential tradeoff.","A clean contrast makes the decision legible.","Then say which you'd pick and why."],"focus":["structure","impact"],"placeholder":"The choice is simple: A protects today's margin, B buys tomorrow's growth."},
    {"id":"narrative-con-early-22","level":"early","profession":"consultant","title":"Building to the ask","scenario":"You need the steering committee to approve funding for phase two. Your draft jumps straight to the ask. A short narrative — what phase one found, why it matters, what phase two unlocks — earns the yes.","task":"Write the 3-sentence build that leads naturally to the funding ask.","tips":["Earn the ask with the finding that motivates it.","Show what the investment unlocks, concretely.","The ask should feel inevitable by the time you make it."],"focus":["structure","impact"]},
    {"id":"narrative-con-early-23","level":"early","profession":"consultant","title":"The reframe that changes the debate","scenario":"The client team is arguing about which region to cut. Your analysis suggests the real question isn't which to cut but whether the cost problem is regional at all. A reframe can move the whole debate to firmer ground.","task":"Write the 2-3 sentences that reframe the question the client is asking.","tips":["Sometimes the persuasive move is changing the question.","Show why the current framing misleads.","Offer the better question, then your answer to it."],"focus":["impact","structure"]},
    {"id":"narrative-con-early-24","level":"early","profession":"consultant","title":"The proof of concept story","scenario":"You're recommending a big change, and the client fears the risk. The persuasive move is a phased story: prove it small first, then scale. A 'test, learn, scale' narrative de-risks the ask.","task":"Write the 2-3 sentence phased narrative that de-risks the recommendation.","tips":["Break a scary change into a safe first step.","'Pilot in one region, prove it, then scale' lowers the barrier.","Show the off-ramp if the pilot fails — that builds trust."],"focus":["impact","structure"]},
    {"id":"narrative-con-early-25","level":"early","profession":"consultant","title":"The closing that calls to action","scenario":"Your section ends by restating the finding and stopping. A persuasive close points forward — it names the decision the client faces and the first concrete step. Findings that don't end in action get admired and shelved.","task":"Write the 2-3 sentence close that turns the finding into a call to act.","tips":["End on the decision, not a recap.","Name the first concrete step and who owns it.","A finding without a next step is a fact, not a recommendation."],"focus":["impact","structure"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-con-early-01","level":"early","profession":"consultant","title":"The slip, front-loaded","scenario":"The analysis you promised the EM for tomorrow won't be ready until Thursday. Your draft buries the new date under three sentences of reasons. Clear is kind — the EM needs the date first to replan.","task":"Write a 2-3 sentence message that leads with the bad news, then the reason.","tips":["Front-load the slip — the EM plans around the date, not the excuse.","One sentence of reason, after.","Say what you're doing to contain the impact."],"focus":["clarity","impact"],"placeholder":"The analysis will land Thursday, not tomorrow. Two experts rescheduled;"},
    {"id":"hard-con-early-02","level":"early","profession":"consultant","title":"The clean no to extra scope","scenario":"A client contact asks you to pull together a side analysis that's outside your workstream and would blow your week. You need to decline clearly without a mushy 'maybe' that leaves it open.","task":"Write a 2-sentence clean no that stays warm and routes it properly.","tips":["A clear no is kinder than a false maybe.","Decline the task, keep the relationship.","Route it: 'that's really a question for [EM] to prioritize'."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-03","level":"early","profession":"consultant","title":"The error that reached the client","scenario":"You found a mistake in a number that's already in the client's hands. You have to tell the EM. Instinct is to cushion; clarity is to state what's wrong, how big, and what you'll do — fast.","task":"Write a 3-sentence message: what's wrong, the impact, the fix.","tips":["State the error plainly in sentence one.","Size the impact so the EM can gauge urgency.","Come with the fix, not just the problem."],"focus":["clarity","impact"],"placeholder":"The savings figure on page 4 is overstated by ~20%. It's already in the client's copy. Here's what I'll do:"},
    {"id":"hard-con-early-04","level":"early","profession":"consultant","title":"Feedback up to a peer","scenario":"A fellow analyst keeps sending you data extracts with unlabeled columns, costing you an hour each time. You need to give peer feedback — behavior, impact, ask — without souring the relationship.","task":"Write a 3-sentence feedback message using behavior, impact, request.","tips":["Name the specific behavior, not a character trait.","State the concrete impact on you or the work.","Make a clear, doable request."],"focus":["clarity","audience"],"placeholder":"When the extracts come without column labels, I spend an hour reverse-engineering them — could you add a header row?"},
    {"id":"hard-con-early-05","level":"early","profession":"consultant","title":"Telling the EM you're overloaded","scenario":"You're staffed on two workstreams and can't do justice to both this week. Saying nothing risks failing both. You need to raise it honestly and propose a fix, not just complain.","task":"Write a 3-sentence message that names the overload and proposes a resolution.","tips":["State the conflict plainly — hiding it fails both streams.","Bring options, not just a problem.","Let the EM make the tradeoff with full information."],"focus":["clarity","impact"]},
    {"id":"hard-con-early-06","level":"early","profession":"consultant","title":"The finding that embarrasses the sponsor","scenario":"Your analysis shows the client sponsor's pet initiative isn't working. You have to include it. The message needs to be clear on the finding while giving the sponsor a dignified path.","task":"Write the 2-3 sentence framing that states the finding honestly and preserves the sponsor's standing.","tips":["Don't soften the finding into meaninglessness.","Separate the initiative's result from the sponsor's judgment.","Offer a forward path so it's not just a verdict."],"focus":["audience","impact"]},
    {"id":"hard-con-early-07","level":"early","profession":"consultant","title":"Declining the client's timeline","scenario":"The client wants the full analysis in a week; it genuinely takes three. Agreeing sets everyone up to fail. You need to say no to the timeline clearly and offer a realistic alternative.","task":"Write a 2-3 sentence message that declines the timeline and offers a real one.","tips":["Don't accept a deadline you'll miss — that's the worse outcome.","State what's achievable in a week versus three.","Offer a phased option: a partial answer sooner."],"focus":["clarity","precision"]},
    {"id":"hard-con-early-08","level":"early","profession":"consultant","title":"Admitting you're stuck","scenario":"You've been quietly struggling with a data problem for two days and hidden it, hoping to solve it. It's not resolving and the deadline is close. You have to tell the EM you're stuck — clearly, early enough to help.","task":"Write a 2-3 sentence message that admits you're stuck and asks for the specific help.","tips":["Admit it early — a two-day-old problem is worse revealed late.","Say exactly where you're stuck, not just 'it's hard'.","Ask for the specific help that would unblock you."],"focus":["clarity","impact"],"placeholder":"I've been stuck on the cost mapping for two days and need help. The specific blocker is:"},
    {"id":"hard-con-early-09","level":"early","profession":"consultant","title":"The pushback on the senior associate's plan","scenario":"The senior associate's proposed analysis plan has a flaw you're fairly sure will waste three days. Raising it risks looking presumptuous; staying silent wastes the days. Deliver the hard message respectfully.","task":"Write a 2-3 sentence message that flags the flaw clearly and respectfully.","tips":["Lead with the concern, framed as a question if that helps.","Give the specific reason, not a vague unease.","Respect the hierarchy without swallowing the point."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-10","level":"early","profession":"consultant","title":"The 'this won't work' to the client","scenario":"A client stakeholder is attached to an idea your analysis shows won't work. You have to tell him — in a way that's clear enough to land but doesn't make him defensive and dig in.","task":"Write a 2-3 sentence message that delivers the hard verdict with a path.","tips":["Be clear the idea doesn't work — softening to nothing helps no one.","Ground it in the specific reason, not opinion.","Offer the alternative that does work."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-11","level":"early","profession":"consultant","title":"The missed detail you own","scenario":"You forgot to include a data source the EM specifically asked for, and it's now too late to fully rework. You have to own the miss without over-apologizing or making excuses.","task":"Write a 2-sentence message that owns the miss cleanly and states the recovery.","tips":["Own it in one line — no cascade of apology.","State what you can still do to recover.","Excuses dilute the ownership; skip them."],"focus":["clarity","impact"]},
    {"id":"hard-con-early-12","level":"early","profession":"consultant","title":"Saying no to the after-hours ask","scenario":"A client contact routinely pings you at 9pm expecting same-night turnarounds on non-urgent requests. You need to set a boundary clearly and warmly, once, rather than seething and complying.","task":"Write a 2-3 sentence message that sets the boundary without damaging the relationship.","tips":["State the boundary plainly and kindly.","Give the alternative: when they can expect a response.","A clear boundary set once beats resentment set nightly."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-13","level":"early","profession":"consultant","title":"The bad news in the stand-up","scenario":"At the team stand-up you have to report that your workstream hit a wall — the data the whole finding depended on doesn't exist. It's tempting to bury it in a hopeful update. Clear is kind: say it straight.","task":"Write the 2-3 sentence stand-up report that leads with the wall and the implication.","tips":["Lead with the wall, not a hopeful preamble.","State what it means for the finding and the timeline.","Bring your proposed pivot."],"focus":["clarity","structure"]},
    {"id":"hard-con-early-14","level":"early","profession":"consultant","title":"Correcting the partner's assumption","scenario":"The partner is about to tell the client something based on an outdated number from your workstream. You have the current number. You have to correct a senior person, fast, before the meeting.","task":"Write the 2-sentence message that corrects the record clearly and without drama.","tips":["State the current number and that it supersedes the old one.","No blame, no drama — just the correction.","Speed matters more than tact here; be clear and quick."],"focus":["clarity","precision"],"placeholder":"Quick correction before the client call: the savings figure is now $3.2M, not $4M —"},
    {"id":"hard-con-early-15","level":"early","profession":"consultant","title":"The disappointing survey result","scenario":"The client hoped the survey would validate their pricing. It didn't — willingness to pay came in well below. You have to deliver the disappointing result without either sugarcoating it or seeming to gloat.","task":"Write the 2-3 sentence delivery of the disappointing finding, honestly and constructively.","tips":["State the result plainly; don't bury it in hedges.","Neutral tone — you're a messenger, not a judge.","Pair it with what it opens up, not just what it closes."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-16","level":"early","profession":"consultant","title":"Telling the EM the data is unusable","scenario":"After two days cleaning the client's dataset, you've concluded it's too broken to support the planned analysis. The EM needs to hear this now to change course, even though it means the last two days produced no finding.","task":"Write the 2-3 sentence message that delivers the verdict and the path forward.","tips":["State the verdict: the data can't support the analysis.","Be specific about why, so it's credible not defeatist.","Propose the alternative approach immediately."],"focus":["clarity","impact"]},
    {"id":"hard-con-early-17","level":"early","profession":"consultant","title":"The peer who took your credit","scenario":"In the team meeting, another analyst presented your analysis as his own. You need to address it with him directly — clear about the behavior and its impact, without exploding.","task":"Write a 3-sentence message that raises it with the peer using behavior, impact, ask.","tips":["Describe what happened factually, not accusingly.","State the impact on you plainly.","Ask for what you want going forward."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-18","level":"early","profession":"consultant","title":"The 'I can't validate this' to the client","scenario":"The client's finance team wants you to sign off on a number you haven't verified and don't fully trust. You have to decline to endorse it — clearly — without accusing anyone of bad data.","task":"Write a 2-3 sentence message that withholds the sign-off honestly.","tips":["Be clear you can't validate it yet, and why.","Frame it as diligence, not distrust.","Offer what it would take to get to yes."],"focus":["clarity","precision"]},
    {"id":"hard-con-early-19","level":"early","profession":"consultant","title":"Flagging the ethical concern","scenario":"You've noticed the team is about to present a benchmark in a way that's technically true but misleading to the client. You have to raise this with the EM — a hard message about the work's integrity.","task":"Write a 2-3 sentence message that raises the concern clearly and constructively.","tips":["Name the specific issue, not a vague discomfort.","Focus on the client's understanding, not on judging colleagues.","Propose the honest alternative framing."],"focus":["clarity","impact"]},
    {"id":"hard-con-early-20","level":"early","profession":"consultant","title":"The realistic no on availability","scenario":"The EM asks if you can join a weekend working session. You have a genuine, unmovable commitment. You need to decline clearly and offer what you can do instead, without over-justifying.","task":"Write a 2-sentence message that declines clearly and offers an alternative.","tips":["A clear no with one line of reason, no elaborate justification.","Offer what you can do: prep ahead, or a different time.","Over-explaining a boundary weakens it."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-21","level":"early","profession":"consultant","title":"The deck won't be ready","scenario":"It's the night before the client meeting and your section clearly won't be finished to standard. The EM needs to know now — to cut scope, get help, or reset expectations — not discover it at 8am.","task":"Write the 2-3 sentence message that raises it tonight with options.","tips":["Raise it now — 8am is too late for the EM to act.","Be specific about what won't be ready.","Bring options: cut, get help, or present partial."],"focus":["clarity","impact"],"placeholder":"Heads-up tonight: my section won't be fully ready for the 9am. Here's where it stands and three options:"},
    {"id":"hard-con-early-22","level":"early","profession":"consultant","title":"The disagreement you have to voice","scenario":"The team is about to recommend a course you believe is wrong for the client. You've stayed quiet. This is your last chance to voice the disagreement before it goes to the partner — a hard message to peers you respect.","task":"Write the 2-3 sentence message that voices the disagreement clearly and respectfully.","tips":["State your disagreement plainly — this is the moment.","Give the specific reason and what you'd do instead.","Disagreeing well is a contribution, not disloyalty."],"focus":["clarity","impact"]},
    {"id":"hard-con-early-23","level":"early","profession":"consultant","title":"Telling the client contact her data was late","scenario":"Your client counterpart's repeated late data delivery is now threatening the deck. You've absorbed it silently. You need to raise it — clearly enough to change behavior, warmly enough to keep the ally.","task":"Write a 3-sentence message that names the pattern, its impact, and the ask.","tips":["Name the pattern factually, without accusation.","Connect it to a shared goal: the deck you both need.","Make a specific, reasonable ask."],"focus":["clarity","audience"]},
    {"id":"hard-con-early-24","level":"early","profession":"consultant","title":"The 'this is over budget' heads-up","scenario":"Your workstream is going to need more hours than scoped, and the EM manages the budget. You have to flag the overrun early and honestly, before it's a surprise on the timesheet.","task":"Write a 2-3 sentence message that flags the overrun with the cause and options.","tips":["Flag it before it happens, not after.","State the cause and the rough size.","Offer a way to contain it: cut scope or add time."],"focus":["clarity","precision"]},
    {"id":"hard-con-early-25","level":"early","profession":"consultant","title":"The hard truth in the retro","scenario":"In the team retro, the honest lesson is that the EM's mid-project scope change cost the team a week. Saying it risks the relationship; not saying it means it recurs. Deliver the hard message constructively.","task":"Write the 2-3 sentence retro comment that names the issue as a process learning, not a personal jab.","tips":["Frame it as a process pattern, not a person's fault.","Use the specific example as evidence, briefly.","Propose the change that would prevent the recurrence."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-con-early-01","level":"early","profession":"consultant","title":"The end-of-week EM email","scenario":"It's Friday and you owe the EM a full workstream update: status, findings, one risk, one decision needed. Everything you've practiced applies at once — lead with the point, structure it, cut the filler, own the recommendation.","task":"Write the complete 4-6 sentence update email, publishable as-is.","tips":["Lead with status and the headline finding.","Structure: status, finding, risk, decision — signposted.","Cut every hedge; own the one decision you need."],"focus":["structure","impact"],"placeholder":"Pricing workstream is on track for Thursday. The headline finding:"},
    {"id":"together-con-early-02","level":"early","profession":"consultant","title":"The client data request, end to end","scenario":"You need three datasets from the client's IT team, on a deadline, and you've never worked with them. Pitch to their language, be precise on fields and dates, lead with the ask, keep it tight.","task":"Write the complete data request email, ready to send.","tips":["Lead with what you need and by when.","Name systems, fields, grain, and date range precisely.","Pitch it in their terms, and make it easy to say yes."],"focus":["audience","precision"]},
    {"id":"together-con-early-03","level":"early","profession":"consultant","title":"The slide headline set","scenario":"Your five-page section needs its headlines written so they lead with the point, form one storyline read together, and each match the exhibit beneath. This is structure, precision, and impact in five lines.","task":"Write the five action-title headlines as a connected storyline.","tips":["Each headline states its page's takeaway as a sentence.","Read in order, they must argue the recommendation.","Each must be provable from its exhibit."],"focus":["structure","impact"]},
    {"id":"together-con-early-04","level":"early","profession":"consultant","title":"The 90-second verbal update","scenario":"The partner drops by and asks how it's going — you have 90 seconds. Lead with the point, structure it, stay precise, own your read, and stop on time. Everything, spoken.","task":"Write the 90-second update as you'd speak it, structured and time-bound.","tips":["Open with the headline, preview the shape.","Finding, one risk, one ask — in that order.","Land it and stop; don't fill the silence."],"focus":["structure","concision"],"placeholder":"Short version: on track, one risk, and I need one call from you —"},
    {"id":"together-con-early-05","level":"early","profession":"consultant","title":"The interview readout, complete","scenario":"You're writing the team readout on ten customer interviews. It needs a spine (three themes), the human voice (quotes), precision (how many said what), and a clear 'so what' for the storyline.","task":"Write the opening and theme structure of the readout, integrating all of it.","tips":["Lead with the strongest takeaway across all ten.","Three themes, each with a count and a quote.","End on what it means for the recommendation."],"focus":["structure","impact"]},
    {"id":"together-con-early-06","level":"early","profession":"consultant","title":"Register shift: same finding, two channels","scenario":"You have to convey one finding two ways: a formal line for the client deck, and a quick Slack to your EM. Same content, different register. Matching register to channel is the skill here.","task":"Write both versions: the deck line and the Slack line.","tips":["Deck: precise, complete, defensible, formal.","Slack: fast, direct, human, still clear.","Same truth, register tuned to the channel."],"focus":["audience","concision"]},
    {"id":"together-con-early-07","level":"early","profession":"consultant","title":"The recommendation email to the senior associate","scenario":"You've finished analyzing three vendor options and need to send your recommendation. Lead with the pick, structure the two reasons, cut the padding, own the call, note the tradeoff. All at once.","task":"Write the complete recommendation email.","tips":["Recommendation in sentence one.","Two reasons, structured; the tradeoff named.","No hedging — you did the work, own the call."],"focus":["impact","structure"],"placeholder":"I recommend Vendor B. Two reasons drive it, and one tradeoff to note:"},
    {"id":"together-con-early-08","level":"early","profession":"consultant","title":"The steering committee pre-read page","scenario":"You're drafting the one-page steerco pre-read. It must be pitched at steerco altitude, structured for a ten-second skim, precise on the decision needed, and honest about the risk. One page, everything.","task":"Write the one-page pre-read content: status, decision needed, risk.","tips":["Steerco altitude — no workstream detail.","Structure: status line, the one decision, the one risk.","Precise on what's needed and by when."],"focus":["audience","structure"]},
    {"id":"together-con-early-09","level":"early","profession":"consultant","title":"The bad-news update, done right","scenario":"Your workstream slipped and you have to tell the EM. Front-load the news, be precise on the new date, structure the options, own your part, propose the recovery. Hard message plus everything else.","task":"Write the complete message: news, cause, options, recommendation.","tips":["Lead with the slip and the new date.","One line of cause; then structured options.","Own your part and recommend a path."],"focus":["clarity","impact"]},
    {"id":"together-con-early-10","level":"early","profession":"consultant","title":"The client-meeting opening","scenario":"You've been asked to open the client working session — two minutes to frame the problem and the decision the room will make. SCQA structure, audience-pitched, concise, and delivered with presence.","task":"Write the two-minute opening as you'd speak it.","tips":["Situation, complication, question — end on the decision.","Pitch to the client's world, not your analysis.","Deliver with quiet conviction; you set the room's tone."],"focus":["structure","impact"],"placeholder":"Today the network runs on five DCs, designed for volumes we've now outgrown by 30%. That raises one question for this room:"},
    {"id":"together-con-early-11","level":"early","profession":"consultant","title":"Edit like a reader","scenario":"You've drafted a dense paragraph for the executive summary. Now read it as the busy partner will: what's the point, is it first, is anything padding, does every number earn its place? Then fix it.","task":"Take your drafted paragraph and rewrite it as a reader-first version.","tips":["Read it as the busiest person who'll receive it.","Point first, padding gone, every number earning its place.","If a sentence doesn't help the reader, cut it."],"focus":["concision","clarity"]},
    {"id":"together-con-early-12","level":"early","profession":"consultant","title":"The exhibit and its title, together","scenario":"You're finalizing a key exhibit. The title must carry the takeaway, the call-out must guide the eye, the numbers must be precise and comparable, and the whole thing must land without narration.","task":"Write the action title and the one guiding call-out for the exhibit.","tips":["Title = the takeaway as a sentence.","Call-out points to where the eye should land first.","Numbers precise, comparison clean, self-explaining."],"focus":["precision","impact"]},
    {"id":"together-con-early-13","level":"early","profession":"consultant","title":"The handoff note that has it all","scenario":"You're rolling off and handing your workstream to a new analyst. Lead with the one live risk, structure what's stable, pitch it for zero context, be precise on files and dates, and be honest about what's shaky.","task":"Write the complete handoff note.","tips":["Open with the one thing they must not miss.","Structure the rest: stable, in-flight, watch-outs.","Zero-context reader: link files, name people by role."],"focus":["structure","audience"]},
    {"id":"together-con-early-14","level":"early","profession":"consultant","title":"The persuasive recommendation slide","scenario":"Your recommendation page must own a clear recommendation, frame the before/after, pre-empt the obvious objection, and end in a call to action — all in the space of one slide's headline and three boxes.","task":"Write the headline and three-box content for the recommendation slide.","tips":["Headline owns the recommendation.","Boxes: why now, what it takes, what it returns.","Pre-empt the top objection in one of them."],"focus":["impact","structure"]},
    {"id":"together-con-early-15","level":"early","profession":"consultant","title":"The question that respects everyone's time","scenario":"You need guidance from the senior associate on a real analytical fork. Lead with the question, give just enough context, make it answerable between meetings, and show you've thought before asking.","task":"Write the complete question message.","tips":["Question first, in one sentence.","Just enough context to answer — no essay.","Show your own lean, so it's a check not a dump."],"focus":["concision","clarity"],"placeholder":"Quick fork I want your read on: size top-down or bottom-up? My lean is bottom-up because —"},
    {"id":"together-con-early-16","level":"early","profession":"consultant","title":"The client update under scrutiny","scenario":"You're sending a status directly to a demanding client sponsor. It must lead with what she cares about, be precise and defensible on every claim, own the recommendation, and pre-empt her likely pushback.","task":"Write the complete client-facing update.","tips":["Lead with her stake, not your activity.","Every claim precise and defensible.","Pre-empt her known pushback in a line."],"focus":["audience","precision"]},
    {"id":"together-con-early-17","level":"early","profession":"consultant","title":"The synthesis under a hard constraint","scenario":"The EM says: 'Give me the whole churn story in three sentences — that's all the partner will read.' You must integrate finding, evidence, and implication under a brutal length limit.","task":"Write exactly three sentences that carry the full churn story.","tips":["Sentence one: the finding.","Sentence two: the decisive evidence.","Sentence three: the implication and the move."],"focus":["concision","impact"],"placeholder":"Two-thirds of churn is driven by service failures, not price."},
    {"id":"together-con-early-18","level":"early","profession":"consultant","title":"The all-in-one Slack thread","scenario":"On Slack, the EM asks a compound question: is the analysis done, is it solid, and can it go to the client? You must answer all three, in order, precisely, and flag the one caveat — in a scannable Slack reply.","task":"Write the complete Slack reply addressing all three parts plus the caveat.","tips":["Answer each of the three, in order.","Precise on the caveat, not vague.","Scannable format — this is Slack, not a memo."],"focus":["structure","clarity"]},
    {"id":"together-con-early-19","level":"early","profession":"consultant","title":"The expert interview debrief","scenario":"Right after an expert call, you send the team the debrief. Lead with the single most useful thing you learned, translate the expert's jargon, be precise about what he claimed versus speculated, and note what it changes.","task":"Write the complete debrief message.","tips":["Lead with the one insight that matters most.","Translate his jargon for the team.","Separate what he knew from what he guessed."],"focus":["audience","precision"]},
    {"id":"together-con-early-20","level":"early","profession":"consultant","title":"The recommendation you have to defend live","scenario":"You'll present your recommendation and take questions. Write the 30-second spoken recommendation and the one-line answer to the toughest question you expect. Presence, structure, precision, and pressure-readiness together.","task":"Write the spoken recommendation and your prepared answer to the hardest question.","tips":["Recommendation: headline, reason, confidence.","Anticipate the toughest question; prepare the specific answer.","Own the number; invite the challenge you're ready for."],"focus":["impact","structure"]},
    {"id":"together-con-early-21","level":"early","profession":"consultant","title":"The cross-audience finding","scenario":"One finding — consolidating DCs saves $3M but adds a day to northeast delivery — must be written two ways: a partner version (the client tension) and a plant-manager version (the operational reality). Audience calibration, end to end.","task":"Write both the partner version and the plant-manager version, 2 sentences each.","tips":["Partner: the client tradeoff and conversation it triggers.","Plant manager: the floor reality and what changes for him.","Same fact, altitude and language tuned to each."],"focus":["audience","impact"]},
    {"id":"together-con-early-22","level":"early","profession":"consultant","title":"The tight, honest risk flag","scenario":"You've spotted a real risk to the engagement's central finding. You must flag it to the EM: lead with the risk, be precise about its size and likelihood, structure the mitigation options, and be honest about what you don't yet know.","task":"Write the complete risk-flag message.","tips":["Lead with the risk and what it threatens.","Precise on size and likelihood, honest on uncertainty.","Structured options, with your recommendation."],"focus":["structure","precision"]},
    {"id":"together-con-early-23","level":"early","profession":"consultant","title":"The polished executive summary paragraph","scenario":"You're writing the executive summary paragraph for your section — the one thing the partner is guaranteed to read. It must lead with the recommendation, structure the support, be precise, own the call, and contain zero filler.","task":"Write the complete executive-summary paragraph.","tips":["Recommendation first, support structured under it.","Every number precise and sourced.","Read it as the partner: cut anything that doesn't earn its place."],"focus":["structure","impact"],"placeholder":"We recommend the client consolidate to three distribution centers, saving ~$3M annually."},
    {"id":"together-con-early-24","level":"early","profession":"consultant","title":"The meeting you have to run","scenario":"You're leading a 15-minute internal working session to align the team on the storyline. You must open with the goal, structure the agenda, keep it moving, and close with clear owners and next steps. Full integration, spoken and live.","task":"Write the opening line, the three-item agenda, and the closing line.","tips":["Open with the one decision the session will reach.","Three agenda items, time-boxed.","Close with owners and next steps, not a fade-out."],"focus":["structure","impact"]},
    {"id":"together-con-early-25","level":"early","profession":"consultant","title":"The capstone: your workstream to the partner","scenario":"The partner asks you directly to summarize your entire workstream — finding, evidence, recommendation, risk — in one minute, spoken, in front of the team. This is everything at once, under the highest-stakes audience you have.","task":"Write the one-minute spoken summary, integrating finding, evidence, recommendation, and risk.","tips":["Headline finding first, then preview the shape.","Recommendation owned, evidence precise, one risk flagged.","Land it in a minute with presence; stop clean."],"focus":["impact","structure"],"placeholder":"Here's the whole workstream in a minute. The finding, the recommendation, and the one risk —"}
  ],
};
